INSERT INTO sega_games (rank, id, title, consoleName, consoleId, totalPlayers, casualPlayers, hardcorePlayers, numAchievements, points, genre, developer, publisher, released, description, icon, boxArt, titleScreen, screenshot, rating) VALUES
  (1, 1, 'Sonic the Hedgehog', 'Genesis/Mega Drive', 1, 53953, 53953, 53953, 35, 0, '2D Platforming', 'Sonic Team', 'Sega', '1991-06-11', 'Sonic the Hedgehog is a Japanese video game series and media franchise created by the Japanese developers Yuji Naka, Naoto Ohshima, and Hirokazu Yasuhara for Sega. The franchise follows Sonic, an anthropomorphic blue hedgehog with supersonic speed, who battles the mad scientist Doctor Eggman and his robot army. The main Sonic the Hedgehog games are platformers mostly developed by Sonic Team; other games, developed by various studios, include spin-offs in the racing, fighting, party and sports genres. The franchise also incorporates printed media, animations, films, and merchandise.', 'https://media.retroachievements.org/Images/085573.png', 'https://media.retroachievements.org/Images/112941.png', 'https://media.retroachievements.org/Images/054993.png', 'https://media.retroachievements.org/Images/000010.png', 5),
  (2, 10, 'Sonic the Hedgehog 2', 'Genesis/Mega Drive', 1, 19942, 19942, 19942, 32, 0, NULL, NULL, NULL, '1992-11-21', 'Sonic the Hedgehog 2 is a 1992 platform game developed by Sega Technical Institute (STI) for the Sega Genesis. Players control Sonic as he attempts to stop Doctor Robotnik from stealing the Chaos Emeralds to power his space station, the Death Egg. Like the first Sonic the Hedgehog (1991), players traverse side-scrolling levels at high speeds while collecting rings, defeating enemies, and fighting bosses. Sonic 2 introduces Sonic''s sidekick Miles Tails Prower and features faster gameplay, larger levels, a multiplayer mode, and special stages featuring pre-rendered 3D graphics.', 'https://media.retroachievements.org/Images/121647.png', 'https://media.retroachievements.org/Images/084488.png', 'https://media.retroachievements.org/Images/054994.png', 'https://media.retroachievements.org/Images/001366.png', 4.8),
  (3, 55, 'Streets of Rage', 'Genesis/Mega Drive', 1, 18521, 18521, 18521, 53, 0, 'Beat ''em Up', 'Sega', 'Sega', '1991-08-02', 'Streets of Rage is a series of side-scrolling beat ''em up video games. It centers on the efforts of several ex-police vigilantes trying to rid the fictional American metropolis of Wood Oak City of a crime syndicate that has corrupted its local government. The first three games in the franchise were developed and released by Sega for the Sega Genesis in the early 1990s and have since been ported and re-released on various platforms. A fourth entry was also released in 2020.', 'https://media.retroachievements.org/Images/110823.png', 'https://media.retroachievements.org/Images/123452.png', 'https://media.retroachievements.org/Images/107662.png', 'https://media.retroachievements.org/Images/107663.png', 4.8),
  (4, 3, 'Streets of Rage 2', 'Genesis/Mega Drive', 1, 18286, 18286, 18286, 22, 0, 'Beat ''em Up', 'Ancient, Sega', 'Sega', '1992-12-15', 'Streets of Rage 2, known as Bare Knuckle II in Japan, is a 1992 beat ''em up video game developed and published by Sega for the Sega Genesis. The sequel to Streets of Rage (1991), the characters Axel Stone and Blaze Fielding return while the game also introduces two new characters: Max Thunder, and Eddie Skate Hunter, the younger brother of Adam Hunter from the first game.', 'https://media.retroachievements.org/Images/120551.png', 'https://media.retroachievements.org/Images/051871.png', 'https://media.retroachievements.org/Images/000212.png', 'https://media.retroachievements.org/Images/000213.png', 4.8),
  (5, 4874, 'Sonic 3 & Knuckles', 'Genesis/Mega Drive', 1, 12975, 12975, 12975, 53, 0, '2D Platforming', 'Sega, Sonic Team', 'Sega', '1994-10-18', 'Sonic the Hedgehog 3 is a 1994 platform game developed by Sega Technical Institute and published by Sega for the Sega Genesis. Like previous Sonic games, players traverse side-scrolling levels while collecting rings and defeating enemies. They control Sonic and Tails, who attempt to retrieve the Chaos Emeralds to stop Doctor Robotnik from relaunching his space station, the Death Egg, after it crash-lands on a mysterious floating island. Sonic 3 introduces Knuckles the Echidna, the island guardian, who lays traps for Sonic and Tails.', 'https://media.retroachievements.org/Images/110373.png', 'https://media.retroachievements.org/Images/116311.png', 'https://media.retroachievements.org/Images/003796.png', 'https://media.retroachievements.org/Images/003797.png', 4.7),
  (6, 69, 'Castlevania: Bloodlines', 'Genesis/Mega Drive', 1, 11750, 11750, 11750, 54, 0, '2D Platforming', 'Konami', 'Konami', '1994-03-17', 'Castlevania: Bloodlines, known in Japan as Vampire Killer and in PAL regions as Castlevania: The New Generation, is a 1994 platform game developed and published by Konami for the Sega Genesis as part of the Castlevania series. A vampire named Elizabeth Bartley is orchestrating the beginning of World War I to serve as the catalyst for the resurrection of her uncle, Dracula. Players take on the role of Quincey Morris'' son, John, and his friend Eric Lecarde to take up the fight against evil.', 'https://media.retroachievements.org/Images/060798.png', 'https://media.retroachievements.org/Images/071778.png', 'https://media.retroachievements.org/Images/067931.png', 'https://media.retroachievements.org/Images/067932.png', 4.6),
  (7, 2, 'Aladdin', 'Genesis/Mega Drive', 1, 11575, 11575, 11575, 21, 0, NULL, NULL, NULL, '1993-10-19', 'Aladdin is a Middle-Eastern folk tale. It is one of the best-known tales associated with One Thousand and One Nights, despite not being part of the original text; it was added by the Frenchman Antoine Galland, based on a folk tale that he heard from the Syrian storyteller Hanna Diyab.', 'https://media.retroachievements.org/Images/123777.png', 'https://media.retroachievements.org/Images/051848.png', 'https://media.retroachievements.org/Images/039378.png', 'https://media.retroachievements.org/Images/000123.png', 4.6),
  (8, 53, 'Comix Zone', 'Genesis/Mega Drive', 1, 11520, 11520, 11520, 41, 0, 'Beat ''em Up', 'Sega', 'Sega', '1995-07-01', 'Comix Zone is a 1995 beat ''em up game developed by Sega Technical Institute (STI) and published by Sega for the Sega Genesis. Set within the panels of a comic book, it follows the comic writer/artist Sketch Turner who, after being transported into the comic by one of his creations, attempts to escape while contending with various threats. The game sees the player traversing six levels, where they interact with the comic world and must defeat enemies, or occasionally solve puzzles, to progress.', 'https://media.retroachievements.org/Images/111299.png', 'https://media.retroachievements.org/Images/046942.png', 'https://media.retroachievements.org/Images/000892.png', 'https://media.retroachievements.org/Images/001373.png', 4.6),
  (9, 282, 'Teenage Mutant Ninja Turtles: The Hyperstone Heist', 'Genesis/Mega Drive', 1, 10670, 10670, 10670, 25, 0, 'Beat ''em Up', 'Konami', 'Konami', '1992-12-01', 'Teenage Mutant Ninja Turtles: The Hyperstone Heist, released in Europe as Teenage Mutant Hero Turtles: The Hyperstone Heist and in Japan as Teenage Mutant Ninja Turtles: Return of the Shredder, is a 1992 beat ''em up game developed and published by Konami for the Sega Genesis, based on the Teenage Mutant Ninja Turtles comic book characters. It was Konami''s debut title for the Genesis. The game was re-released as part of Teenage Mutant Ninja Turtles: The Cowabunga Collection in 2022.', 'https://media.retroachievements.org/Images/123099.png', 'https://media.retroachievements.org/Images/116471.png', 'https://media.retroachievements.org/Images/048578.png', 'https://media.retroachievements.org/Images/048579.png', 4.6),
  (10, 18, 'Golden Axe', 'Genesis/Mega Drive', 1, 10320, 10320, 10320, 24, 0, 'Beat ''em Up', 'Sega', 'Sega', '1989-12-23', 'Golden Axe  is a series of side-scrolling beat ''em up arcade video games developed by Sega. The series takes place in a medieval fantasy world where several heroes have the task of recovering the legendary Golden Axe, the mainstay element of the series.', 'https://media.retroachievements.org/Images/016753.png', 'https://media.retroachievements.org/Images/051935.png', 'https://media.retroachievements.org/Images/048564.png', 'https://media.retroachievements.org/Images/048565.png', 4.6),
  (11, 21, 'Sonic the Hedgehog 3', 'Genesis/Mega Drive', 1, 9605, 9605, 9605, 29, 0, '2D Platforming', 'Sega, Sonic Team', 'Sega', '1994-02-02', 'Sonic the Hedgehog 3 is a 1994 platform game developed by Sega Technical Institute and published by Sega for the Sega Genesis. Like previous Sonic games, players traverse side-scrolling levels while collecting rings and defeating enemies. They control Sonic and Tails, who attempt to retrieve the Chaos Emeralds to stop Doctor Robotnik from relaunching his space station, the Death Egg, after it crash-lands on a mysterious floating island. Sonic 3 introduces Knuckles the Echidna, the island guardian, who lays traps for Sonic and Tails.', 'https://media.retroachievements.org/Images/110369.png', 'https://media.retroachievements.org/Images/051937.png', 'https://media.retroachievements.org/Images/054995.png', 'https://media.retroachievements.org/Images/119270.png', 4.6),
  (12, 263, 'Michael Jackson''s Moonwalker', 'Genesis/Mega Drive', 1, 9288, 9288, 9288, 50, 0, 'Beat ''em Up', 'Sega', 'Sega', '1990-08-25', 'In 1990, several video games based on the 1988 Michael Jackson film Moonwalker, all named Michael Jackson''s Moonwalker, were released. Sega developed two beat ''em ups, one released in arcades and another released for the Sega Genesis and Master System consoles. U.S. Gold also published various games for home computers. Each of the games'' plots loosely follows the Smooth Criminal segment of the film, in which Jackson rescues kidnapped children from the evil Mr. Big, and incorporates synthesized versions of some of the musician''s songs. Following Moonwalker, Jackson collaborated with Sega on several other video games.', 'https://media.retroachievements.org/Images/047868.png', 'https://media.retroachievements.org/Images/014236.png', 'https://media.retroachievements.org/Images/040977.png', 'https://media.retroachievements.org/Images/048231.png', 4.6),
  (13, 9, 'Castle of Illusion starring Mickey Mouse', 'Genesis/Mega Drive', 1, 8104, 8104, 8104, 20, 0, NULL, 'Sega', 'Sega', '1990-11-21', 'Castle of Illusion Starring Mickey Mouse is a 1990 platform game developed and published by Sega and released for the Sega Genesis. An 8-bit version of the game was later released for the Master System and Game Gear. The game follows Mickey Mouse on a quest to save Minnie Mouse from the evil witch Mizrabel. It is the first game in Sega''s Illusion video game series starring Mickey.', 'https://media.retroachievements.org/Images/048628.png', 'https://media.retroachievements.org/Images/051879.png', 'https://media.retroachievements.org/Images/000776.png', 'https://media.retroachievements.org/Images/000777.png', 4.6),
  (14, 24, 'Altered Beast', 'Genesis/Mega Drive', 1, 7644, 7644, 7644, 26, 0, 'Beat ''em Up', 'Sega', 'Sega', '1988-11-27', 'Altered Beast is a 1988 beat ''em up video game developed by Team Shinobi and published by Sega for arcades. Set in Ancient Greece, the game follows a Roman centurion who is resurrected by the Olympian god Zeus to rescue his daughter Athena from Neff, the demonic ruler of the underworld. By collecting three power-ups in a level, the player character can transform into one of five mythical beasts.', 'https://media.retroachievements.org/Images/088907.png', 'https://media.retroachievements.org/Images/051941.png', 'https://media.retroachievements.org/Images/039525.png', 'https://media.retroachievements.org/Images/039526.png', 4.6),
  (15, 168, 'The Adventures of Batman & Robin', 'Genesis/Mega Drive', 1, 6442, 6442, 6442, 13, 0, 'Run & Gun', 'Clockwork Tortoise', 'Sega', '1995-08-02', 'Batman: The Animated Series is an American animated superhero television series based on the DC Comics superhero Batman. Developed by Bruce Timm and Eric Radomski, and produced by Warner Bros. Animation, it originally aired on Fox Kids from September 5, 1992, to September 15, 1995, with a total of 85 episodes. Mid-way through the series'' run, it was re-titled The Adventures of Batman & Robin.', 'https://media.retroachievements.org/Images/061855.png', 'https://media.retroachievements.org/Images/121188.png', 'https://media.retroachievements.org/Images/039423.png', 'https://media.retroachievements.org/Images/039424.png', 4.5),
  (16, 169, 'Sonic & Knuckles', 'Genesis/Mega Drive', 1, 6243, 6243, 6243, 20, 0, '2D Platforming', 'Sega, Sonic Team', 'Sega', '1994-10-18', 'Sonic & Knuckles is a 1994 platform game developed by Sega Technical Institute and published by Sega for the Sega Genesis. Players control Sonic the Hedgehog or Knuckles the Echidna in their quests to save Angel Island; Sonic tries to stop Doctor Robotnik from re-launching his orbital weapon, the Death Egg, while Knuckles scuffles with Robotnik''s minion, EggRobo. Like previous Sonic games, players traverse side-scrolling levels at high speeds while collecting rings and defeating enemies.', 'https://media.retroachievements.org/Images/110372.png', 'https://media.retroachievements.org/Images/116310.png', 'https://media.retroachievements.org/Images/000125.png', 'https://media.retroachievements.org/Images/119269.png', 4.5),
  (17, 11, 'Earthworm Jim', 'Genesis/Mega Drive', 1, 6242, 6242, 6242, 117, 0, NULL, NULL, NULL, '1994-10-01', 'Earthworm Jim is a series of platform games featuring an earthworm named Jim who wears a robotic suit and battles the forces of evil. The series is noted for its platforming and shooting gameplay, surreal humor, and edgy art style. Four games were released in the series: Earthworm Jim, Earthworm Jim 2, Earthworm Jim 3D, and Earthworm Jim: Menace 2 the Galaxy, with the first game released in 1994. The series had lain dormant for almost a decade before Gameloft remade the original game in HD for PlayStation Network and Xbox Live Arcade in 2010. Interplay announced Earthworm Jim 4 in 2008; little to no information surfaced until May 2019 and August 2020, and development was believed cancelled by the rights owners by 2023, as it had never left pre-planning stages.', 'https://media.retroachievements.org/Images/115155.png', 'https://media.retroachievements.org/Images/051915.png', 'https://media.retroachievements.org/Images/000888.png', 'https://media.retroachievements.org/Images/000889.png', 4.5),
  (18, 7, 'Gunstar Heroes', 'Genesis/Mega Drive', 1, 6214, 6214, 6214, 54, 0, NULL, NULL, NULL, '1993-09-09', 'Gunstar Heroes is a 1993 run and gun video game developed by Treasure and published by Sega for the Sega Genesis. It was Treasure''s first developed video game. The premise is centered around a pair of characters, the Gunstars, in their efforts to stop an evil empire from recovering four powerful gems. The characters can fire guns and perform a series of acrobatic maneuvers to fight enemies across each stage. There are four weapons which can be combined with one another to create different shot types.', 'https://media.retroachievements.org/Images/044564.png', 'https://media.retroachievements.org/Images/051875.png', 'https://media.retroachievements.org/Images/000183.png', 'https://media.retroachievements.org/Images/000184.png', 4.5),
  (19, 54, 'Streets of Rage 3', 'Genesis/Mega Drive', 1, 6187, 6187, 6187, 48, 0, 'Beat ''em Up', 'Sega', 'Sega', '1994-06-01', 'Streets of Rage 3 is a 1994 beat ''em up game developed and published by Sega for the Genesis. It is the third installment of the Streets of Rage series and the last game in the original trilogy. The game includes several changes over Streets of Rage and Streets of Rage 2, such as a more complex plot, inclusion of character dialogue, longer levels, more in-depth scenarios and faster gameplay. Weapons can be integrated with unique moves with certain characters, hidden characters were added, and a few cutscenes were included to give the story greater depth.', 'https://media.retroachievements.org/Images/110827.png', 'https://media.retroachievements.org/Images/000598.png', 'https://media.retroachievements.org/Images/053237.png', 'https://media.retroachievements.org/Images/000596.png', 4.5),
  (20, 15, 'Sonic the Hedgehog Spinball', 'Genesis/Mega Drive', 1, 6068, 6068, 6068, 68, 0, NULL, NULL, NULL, '1993-11-15', 'Sonic Spinball, also known as Sonic the Hedgehog Spinball, is a 1993 pinball video game developed by Sega Technical Institute and published by Sega for the Sega Genesis. It is a spin-off of the Sonic the Hedgehog series. Players control Sonic the Hedgehog, who must stop Doctor Robotnik from enslaving the population in a giant pinball-like mechanism. The game is set in a series of pinball machine-like environments with Sonic acting as the pinball.', 'https://media.retroachievements.org/Images/077489.png', 'https://media.retroachievements.org/Images/051932.png', 'https://media.retroachievements.org/Images/000703.png', 'https://media.retroachievements.org/Images/000702.png', 4.5),
  (21, 120, 'Contra: Hard Corps', 'Genesis/Mega Drive', 1, 6063, 6063, 6063, 80, 0, 'Run & Gun', 'Konami', 'Konami', '1994-09-15', 'Contra: Hard Corps, released as Contra: The Hard Corps in Japan and Probotector in Europe and Australia, is a 1994 run and gun game developed and published by Konami for the Sega Genesis, making it the first game in the Contra series released for a Sega platform.', 'https://media.retroachievements.org/Images/093812.png', 'https://media.retroachievements.org/Images/046239.png', 'https://media.retroachievements.org/Images/001098.png', 'https://media.retroachievements.org/Images/001099.png', 4.5),
  (22, 64, 'Shinobi III: Return of the Ninja Master', 'Genesis/Mega Drive', 1, 6009, 6009, 6009, 49, 0, 'Action', 'Sega', 'Sega', '1993-07-23', 'Shinobi III: Return of the Ninja Master, released in Japan as The Super Shinobi II, is a 1993 hack and slash platform game developed and published by Sega for the Sega Genesis. It is the direct sequel to the previous The Revenge of Shinobi. Shinobi III received critical acclaim and has been ranked among the greatest Genesis games.', 'https://media.retroachievements.org/Images/087670.png', 'https://media.retroachievements.org/Images/064148.png', 'https://media.retroachievements.org/Images/064151.png', 'https://media.retroachievements.org/Images/064150.png', 4.5),
  (23, 212, 'Ghouls ''n Ghosts', 'Genesis/Mega Drive', 1, 5788, 5788, 5788, 23, 0, NULL, 'Capcom', 'Capcom', '1989-08-03', 'Ghouls ''n Ghosts, known as Dai Makaimura in Japan, is a 1988 platform game developed and published by Capcom for arcades. It is the sequel to 1985''s Ghosts ''n Goblins, and the second game in the Ghosts ''n Goblins series.', 'https://media.retroachievements.org/Images/119071.png', 'https://media.retroachievements.org/Images/000176.png', 'https://media.retroachievements.org/Images/048561.png', 'https://media.retroachievements.org/Images/048562.png', 4.5),
  (24, 480, 'Alien Soldier', 'Genesis/Mega Drive', 1, 5493, 5493, 5493, 40, 0, 'Run & Gun', 'Treasure', 'Sega', '1995-02-24', 'Alien Soldier is a 1995 run and gun video game developed by Treasure and published by Sega for the Mega Drive. Retail copies were released in Japan and PAL territories while in North America it was only available exclusively via the Sega Channel cable service. The story follows a powerful being named Epsilon-Eagle, who after being nearly killed becomes determined to avenge his near death and save his planet. The character has a variety of weapons and moves that the player must master to complete the game. Many gameplay ideas are borrowed from Treasure''s earlier Mega Drive release, Gunstar Heroes (1993). However, Alien Soldier puts an emphasis on challenging boss fights with short and easy levels serving as downtime in-between.', 'https://media.retroachievements.org/Images/073853.png', 'https://media.retroachievements.org/Images/001072.png', 'https://media.retroachievements.org/Images/001069.png', 'https://media.retroachievements.org/Images/001070.png', 4.5),
  (25, 87, 'Golden Axe II', 'Genesis/Mega Drive', 1, 5417, 5417, 5417, 32, 0, 'Beat ''em Up', 'Sega', 'Sega', '1991-12-27', 'Golden Axe II is a 1991 beat ''em up video game developed and published by Sega for the Sega Genesis. It is a sequel to 1989''s Golden Axe, and the second installment of the Golden Axe series. The player controls one of three warriors as they attempt to recover the Golden Axe by slaying Dark Guld and his loyal followers. Much like its predecessor, the gameplay is based around side-scrolling levels where the player fights enemies by using their melee weapon, while riding a beast, or utilizing elemental magic. The game revamps and introduces various gameplay mechanics from its contemporary including the ability to select the level of magic used and an attack that hits all around the player’s character.', 'https://media.retroachievements.org/Images/016754.png', 'https://media.retroachievements.org/Images/048566.png', 'https://media.retroachievements.org/Images/048567.png', 'https://media.retroachievements.org/Images/048568.png', 4.5),
  (26, 145, 'Columns', 'Genesis/Mega Drive', 1, 5347, 5347, 5347, 24, 0, NULL, 'Sega', 'Sega', '1990-06-30', 'A column or pillar in architecture and structural engineering is a structural element that transmits, through compression, the weight of the structure above to other structural elements below. In other words, a column is a compression member. The term column applies especially to a large round support with a capital and a base or pedestal, which is made of stone, or appearing to be so. A small wooden or metal support is typically called a post. Supports with a rectangular or other non-round section are usually called piers. Throughout architectural history, especially in Classical and Rennaisance styles, the column has been central to building design.', 'https://media.retroachievements.org/Images/049263.png', 'https://media.retroachievements.org/Images/001479.png', 'https://media.retroachievements.org/Images/001477.png', 'https://media.retroachievements.org/Images/001478.png', 4.5),
  (27, 209, 'Dr. Robotnik''s Mean Bean Machine', 'Genesis/Mega Drive', 1, 5344, 5344, 5344, 34, 0, 'Falling Block Puzzle', 'Compile', 'Sega', '1993-11-26', 'Dr. Robotnik''s Mean Bean Machine is a falling block puzzle video game developed by Compile and published by Sega. It was released for the Sega Genesis / Mega Drive and Game Gear in 1993 and ported to the Master System in 1994.', 'https://media.retroachievements.org/Images/108516.png', 'https://media.retroachievements.org/Images/075913.png', 'https://media.retroachievements.org/Images/075911.png', 'https://media.retroachievements.org/Images/075912.png', 4.5),
  (28, 218, 'QuackShot starring Donald Duck', 'Genesis/Mega Drive', 1, 5309, 5309, 5309, 31, 0, '2D Platforming', 'Sega', 'Sega', '1991-12-19', 'QuackShot Starring Donald Duck, known in Japan as I Love Donald Duck: The Treasure of King Garuzia, is a 1991 platform game developed and published by Sega for the Sega Genesis. The player controls Donald Duck as he, alongside his three nephews Huey, Dewey and Louie, attempt to track down a lost artifact which was treasured by King Garuzia. The game was influenced by the Indiana Jones film series.', 'https://media.retroachievements.org/Images/114167.png', 'https://media.retroachievements.org/Images/116307.png', 'https://media.retroachievements.org/Images/000971.png', 'https://media.retroachievements.org/Images/000972.png', 4.5),
  (29, 45, 'Batman: The Video Game', 'Genesis/Mega Drive', 1, 5258, 5258, 5258, 17, 0, '2D Platforming', 'Sunsoft', 'Sega', '1990-07-27', 'Batman: The Video Game is a platformer developed by Sunsoft for the Nintendo Entertainment System featuring the DC Comics character Batman, tying into the 1989 film of the same name.', 'https://media.retroachievements.org/Images/053393.png', 'https://media.retroachievements.org/Images/048583.png', 'https://media.retroachievements.org/Images/048584.png', 'https://media.retroachievements.org/Images/048585.png', 4.5),
  (30, 8, 'Ecco the Dolphin', 'Genesis/Mega Drive', 1, 4926, 4926, 4926, 41, 0, NULL, NULL, NULL, '1992-12-01', 'Ecco the Dolphin is a series of action-adventure video games developed by Appaloosa Interactive and published by Sega.', 'https://media.retroachievements.org/Images/117042.png', 'https://media.retroachievements.org/Images/051877.png', 'https://media.retroachievements.org/Images/051878.png', 'https://media.retroachievements.org/Images/001120.png', 4.5),
  (31, 68, 'Kid Chameleon', 'Genesis/Mega Drive', 1, 4843, 4843, 4843, 65, 0, '2D Platforming', 'Sega', 'Sega', '1992-05-29', 'Kid Chameleon is a 1992 platform game developed and published by Sega for the Sega Genesis. The player controls the Kid Chameleon and attempts to save his peers from a virtual reality video game''s rogue artificial intelligence. The gameplay involves the player going through a series of levels, in which the goal is to reach a flag at the end. The central mechanic revolves around different forms, obtained from masks, which are used to progress through levels.', 'https://media.retroachievements.org/Images/113104.png', 'https://media.retroachievements.org/Images/041967.png', 'https://media.retroachievements.org/Images/001136.png', 'https://media.retroachievements.org/Images/041968.png', 4.4),
  (32, 293, 'Thunder Force IV', 'Genesis/Mega Drive', 1, 4834, 4834, 4834, 36, 0, 'Shoot ''em Up', 'Technosoft | Tecno Soft', 'Sega', '1992-07-24', 'Thunder Force IV, known in North America as Lightening Force: Quest for the Darkstar, is a 1992 shoot ''em up video game developed and published by Technosoft for the Mega Drive/Genesis. It is the fourth installment in Technosoft''s Thunder Force series, and the third and final one created for the Mega Drive. It was developed by the team at Technosoft that ported Devil''s Crush to the Mega Drive rather than the team that developed the previous Thunder Force games. Like its predecessors, it is a horizontally scrolling shooter, but it also features extensive vertical scrolling with large playing fields.', 'https://media.retroachievements.org/Images/004975.png', 'https://media.retroachievements.org/Images/005003.png', 'https://media.retroachievements.org/Images/004974.png', 'https://media.retroachievements.org/Images/005002.png', 4.4),
  (33, 326, 'Sonic 3D Blast', 'Genesis/Mega Drive', 1, 4710, 4710, 4710, 85, 0, '2.5D Platforming', 'Sonic Team, Traveller''s Tales', 'Sega', '1996-01-01', 'Sonic 3D Blast, known in regions outside North America as Sonic 3D: Flickies'' Island, is a 1996 platform game in the Sonic the Hedgehog series for the Sega Genesis and Sega Saturn. As Sonic the Hedgehog, the player embarks on a journey to save the Flickies, birds enslaved by Doctor Robotnik. The player must guide Sonic through a series of themed levels to collect Flickies and defeat Robotnik. Though it retains game mechanics from prior Sonic games, Sonic 3D Blast is differentiated by its 2D isometric perspective, with pre-rendered 3D models converted into sprites.', 'https://media.retroachievements.org/Images/098168.png', 'https://media.retroachievements.org/Images/120745.png', 'https://media.retroachievements.org/Images/120743.png', 'https://media.retroachievements.org/Images/120744.png', 4.4),
  (34, 66, 'Splatterhouse 2', 'Genesis/Mega Drive', 1, 4350, 4350, 4350, 20, 0, 'Beat ''em Up', 'Now Production', 'Namco', '1992-08-03', 'Splatterhouse 2, known in Japan as Splatterhouse Part 2, is a 1992 beat ''em up video game developed by Now Production and published by Namco for the Sega Genesis. It is the sequel to the 1988 arcade game Splatterhouse, and the third installment in the Splatterhouse series, following Splatterhouse: Wanpaku Graffiti.', 'https://media.retroachievements.org/Images/048203.png', 'https://media.retroachievements.org/Images/003605.png', 'https://media.retroachievements.org/Images/003606.png', 'https://media.retroachievements.org/Images/003607.png', 4.4),
  (35, 79, 'Mortal Kombat', 'Genesis/Mega Drive', 1, 4246, 4246, 4246, 39, 0, '2D Fighting', 'Probe Entertainment', 'Midway, Arena Entertainment', '1993-09-13', 'Mortal Kombat is an American media franchise centered on a series of fighting video games originally developed by Midway Games in 1992.', 'https://media.retroachievements.org/Images/054555.png', 'https://media.retroachievements.org/Images/060065.png', 'https://media.retroachievements.org/Images/036199.png', 'https://media.retroachievements.org/Images/036201.png', 4.4),
  (36, 40, 'World of Illusion starring Mickey Mouse and Donald Duck', 'Genesis/Mega Drive', 1, 4243, 4243, 4243, 36, 0, '2D Platforming', 'Sega', 'Sega', '1992-12-14', 'Castle of Illusion Starring Mickey Mouse is a 1990 platform game developed and published by Sega and released for the Sega Genesis. An 8-bit version of the game was later released for the Master System and Game Gear. The game follows Mickey Mouse on a quest to save Minnie Mouse from the evil witch Mizrabel. It is the first game in Sega''s Illusion video game series starring Mickey.', 'https://media.retroachievements.org/Images/116068.png', 'https://media.retroachievements.org/Images/000319.png', 'https://media.retroachievements.org/Images/000316.png', 'https://media.retroachievements.org/Images/005364.png', 4.4),
  (37, 644, 'M.U.S.H.A.: Metallic Uniframe Super Hybrid Armor', 'Genesis/Mega Drive', 1, 4117, 4117, 4117, 30, 0, 'Shoot ''em Up', 'Compile', 'Toaplan, Seismic', '1990-12-21', 'MUSHA is a vertically scrolling shooter video game developed by Compile for the Sega Genesis. An entry in Compile''s shooter series, Aleste, MUSHA places the player in the role of a flying mecha pilot who must destroy a large super intelligent computer threatening planet Earth. The game had a working title of Aleste 2 and originally featured a style similar to the first game, but this was changed to a more original Japanese aesthetic and speed metal soundtrack.', 'https://media.retroachievements.org/Images/047648.png', 'https://media.retroachievements.org/Images/047599.png', 'https://media.retroachievements.org/Images/000666.png', 'https://media.retroachievements.org/Images/000667.png', 4.4),
  (38, 20, 'Alex Kidd in the Enchanted Castle', 'Genesis/Mega Drive', 1, 4082, 4082, 4082, 66, 0, '2D Platforming', 'Overworks', 'Sega', '1989-02-10', 'Alex Kidd in the Enchanted Castle is a 1989 platform game developed and published by Sega for the Genesis. It is the only 16-bit platform game starring Alex Kidd, and the fifth game in the Alex Kidd series.', 'https://media.retroachievements.org/Images/047131.png', 'https://media.retroachievements.org/Images/051936.png', 'https://media.retroachievements.org/Images/000492.png', 'https://media.retroachievements.org/Images/000493.png', 4.4),
  (39, 494, 'Mega Bomberman', 'Genesis/Mega Drive', 1, 4025, 4025, 4025, 40, 0, 'Action', NULL, 'Sega', '1994-11-01', 'Bomberman ''94  is an action maze video game in the Bomberman series developed and published by Hudson Soft for the PC Engine and released on December 10, 1993, in Japan. It was later re-developed by Westone and re-published by Sega as Mega Bomberman on the Sega Mega Drive/Genesis in 1994 in other areas. The PC Engine Bomberman ''94 was later released outside Japan through the Virtual Console and the PlayStation Network.', 'https://media.retroachievements.org/Images/114059.png', 'https://media.retroachievements.org/Images/114051.png', 'https://media.retroachievements.org/Images/082568.png', 'https://media.retroachievements.org/Images/006752.png', 4.4),
  (40, 42, 'Tiny Toon Adventures: Buster''s Hidden Treasure', 'Genesis/Mega Drive', 1, 3975, 3975, 3975, 98, 0, '2D Platforming', 'Konami', 'Konami', '1993-01-01', 'Tiny Toon Adventures: Buster''s Hidden Treasure is the first Tiny Toon Adventures-based game released on the Sega Genesis. It was released in 1993 and developed and published by Konami. The game was not released in Japan, but was released in South Korea, where it was simply called Tiny Toons Adventures.', 'https://media.retroachievements.org/Images/023861.png', 'https://media.retroachievements.org/Images/001213.png', 'https://media.retroachievements.org/Images/001210.png', 'https://media.retroachievements.org/Images/001211.png', 4.4),
  (41, 94, 'The Revenge of Shinobi', 'Genesis/Mega Drive', 1, 3974, 3974, 3974, 44, 0, '2D Platforming, Action', 'Sega', 'Sega', '1989-12-02', 'The Revenge of Shinobi, released in Japan as The Super Shinobi, is a hack-and-slash action video game developed and published by Sega in 1989. It was the first Shinobi game developed for the Sega Genesis, and was later released on the coin-operated version of that console, the Mega-Tech.', 'https://media.retroachievements.org/Images/072086.png', 'https://media.retroachievements.org/Images/054914.png', 'https://media.retroachievements.org/Images/019748.png', 'https://media.retroachievements.org/Images/000197.png', 4.4),
  (42, 93, 'The Lion King', 'Genesis/Mega Drive', 1, 3917, 3917, 3917, 24, 0, '2D Platforming', 'Westwood Studios | Westwood Associates', 'Virgin Interactive', '1994-12-08', 'The Lion King is a 1994 American animated musical drama film directed by Roger Allers and Rob Minkoff, produced by Don Hahn, and written by Irene Mecchi, Jonathan Roberts, and Linda Woolverton. It was produced by Walt Disney Feature Animation, and features an ensemble voice cast consisting of Matthew Broderick, James Earl Jones, Jeremy Irons, Jonathan Taylor Thomas, Moira Kelly, Niketa Calame, Nathan Lane, Ernie Sabella, Whoopi Goldberg, Cheech Marin, Rowan Atkinson, and Robert Guillaume. The story follows a young lion prince named Simba, who is exiled from his kingdom after his father Mufasa is murdered by his uncle Scar to seize the throne. As he grows up, Simba must decide whether to return home to confront Scar and reclaim his place as king.', 'https://media.retroachievements.org/Images/115225.png', 'https://media.retroachievements.org/Images/000326.png', 'https://media.retroachievements.org/Images/115122.png', 'https://media.retroachievements.org/Images/115123.png', 4.4),
  (43, 102, 'X-Men', 'Genesis/Mega Drive', 1, 3828, 3828, 3828, 32, 0, 'Action, Platforming', 'Western Technologies', 'Sega', '1993-01-01', 'The X-Men are a superhero team in American comic books published by Marvel Comics. Created by writer/editor Stan Lee and artist/co-plotter Jack Kirby, the team first appeared in The X-Men #1. Although initially cancelled in 1970 due to low sales, following its 1975 revival and subsequent direction under writer Chris Claremont, it became one of Marvel Comics''s most recognizable and successful franchises. They have appeared in numerous books, television shows, 20th Century Fox''s X-Men films, and video games. The X-Men title may refer to the superhero team itself, the eponymous comic series, or the broader franchise, which includes various solo titles and team books, such as the New Mutants, Excalibur, and X-Force.', 'https://media.retroachievements.org/Images/125065.png', 'https://media.retroachievements.org/Images/020589.png', 'https://media.retroachievements.org/Images/020587.png', 'https://media.retroachievements.org/Images/020588.png', 4.4),
  (44, 110, 'Sunset Riders', 'Genesis/Mega Drive', 1, 3677, 3677, 3677, 15, 0, NULL, 'Konami', 'Konami', '1993-01-01', 'Sunset Riders is a 1991 run and gun video game developed and published by Konami for arcades. It was released in North America in October 1991 and Japan in November 1991. It is set in the American Old West, where the player(s) take control of bounty hunters who are seeking the rewards offered for various criminals.', 'https://media.retroachievements.org/Images/052907.png', 'https://media.retroachievements.org/Images/000195.png', 'https://media.retroachievements.org/Images/000192.png', 'https://media.retroachievements.org/Images/000193.png', 4.4),
  (45, 211, 'Alien Storm', 'Genesis/Mega Drive', 1, 3662, 3662, 3662, 12, 0, 'Rail Shooter, Run & Gun', 'Overworks', 'Sega', '1991-06-28', 'Alien Storm (エイリアンストーム) is a beat ''em up shooter released as an arcade video game by Sega in 1990. It was ported to the Genesis/Mega Drive and Master System. The Mega Drive version was re-released on Wii''s Virtual Console in 2007 and was also included on Sonic''s Ultimate Genesis Collection for Xbox 360 and PlayStation 3. The game was also re-released on the Nintendo Classics service in 2022.', 'https://media.retroachievements.org/Images/089349.png', 'https://media.retroachievements.org/Images/003500.png', 'https://media.retroachievements.org/Images/000545.png', 'https://media.retroachievements.org/Images/000542.png', 4.4),
  (46, 39, 'Alisia Dragoon', 'Genesis/Mega Drive', 1, 3608, 3608, 3608, 39, 0, '2D Platforming', 'Game Arts', NULL, '1992-03-30', 'Alisia Dragoon is a 1992 platform game developed by Game Arts and published by Sega for the Sega Genesis. The player controls Alisia, a young woman who is on a quest to avenge her father and save the world. She can fire lightning from her hands and summon four faithful beasts to aid her. The game was later made available on the Sega Genesis Mini and Nintendo Classics service.', 'https://media.retroachievements.org/Images/005880.png', 'https://media.retroachievements.org/Images/028450.png', 'https://media.retroachievements.org/Images/048204.png', 'https://media.retroachievements.org/Images/049852.png', 4.4),
  (47, 6312, 'Knuckles the Echidna in Sonic the Hedgehog 2', 'Genesis/Mega Drive', 1, 3570, 3570, 3570, 26, 0, '2D Platforming', 'Sega, Sonic Team', 'Sega', '1994-10-18', 'Sonic the Hedgehog 2 is a 1992 platform game developed by Sega Technical Institute (STI) for the Sega Genesis. Players control Sonic as he attempts to stop Doctor Robotnik from stealing the Chaos Emeralds to power his space station, the Death Egg. Like the first Sonic the Hedgehog (1991), players traverse side-scrolling levels at high speeds while collecting rings, defeating enemies, and fighting bosses. Sonic 2 introduces Sonic''s sidekick Miles Tails Prower and features faster gameplay, larger levels, a multiplayer mode, and special stages featuring pre-rendered 3D graphics.', 'https://media.retroachievements.org/Images/121673.png', 'https://media.retroachievements.org/Images/009353.png', 'https://media.retroachievements.org/Images/009350.png', 'https://media.retroachievements.org/Images/009352.png', 4.4),
  (48, 2166, 'Thunder Force III', 'Genesis/Mega Drive', 1, 3561, 3561, 3561, 28, 0, 'Shoot ''em Up', NULL, 'Sega', '1990-06-08', 'Thunder Force III (サンダーフォースIII) is a 1990 scrolling shooter game developed by Technosoft for the Sega Genesis. It is the third chapter in the Thunder Force series. It was then retooled into an arcade game named Thunder Force AC. In 1991, Thunder Force AC was ported to the Super Nintendo Entertainment System under the title Thunder Spirits.', 'https://media.retroachievements.org/Images/078307.png', 'https://media.retroachievements.org/Images/000831.png', 'https://media.retroachievements.org/Images/000829.png', 'https://media.retroachievements.org/Images/000830.png', 4.4),
  (49, 98, 'Shadow Dancer: The Secret of Shinobi', 'Genesis/Mega Drive', 1, 3533, 3533, 3533, 19, 0, '2D Platforming', 'Sega', 'Sega', '1990-12-01', 'Shadow Dancer: The Secret of Shinobi , also known simply as Shadow Dancer, is a side-scrolling action game developed and published by Sega for the Sega Genesis in 1990. It is the second game in the Shinobi series released for the Mega Drive, following The Revenge of Shinobi. However, it is not a continuation of the previous game, but rather a loose adaptation of the 1989 arcade game Shadow Dancer. Like in the original arcade game, the player controls a ninja followed by a canine companion. The Secret of Shinobi was well received by critics.', 'https://media.retroachievements.org/Images/085627.png', 'https://media.retroachievements.org/Images/034046.png', 'https://media.retroachievements.org/Images/001185.png', 'https://media.retroachievements.org/Images/001186.png', 4.4),
  (50, 137, 'Battletoads', 'Genesis/Mega Drive', 1, 3490, 3490, 3490, 33, 0, 'Beat ''em Up', 'Arc System Works', 'Sega', '1991-06-01', 'Battletoads is a video game franchise by Rare that began with the original beat ''em up game Battletoads in 1991. Starring three anthropomorphic toads named after skin conditions, Rash, Zitz, and Pimple, the series was created to rival the Teenage Mutant Ninja Turtles games series. The original Battletoads game for the NES was renowned for its extreme difficulty, but still received a cult following, spawning sequels for various platforms including a crossover with the Double Dragon series and a modern reboot after a 25-year gap in releases. In each of the games, the objective is to defeat the toads'' nemesis the Dark Queen and her army of space mutants.', 'https://media.retroachievements.org/Images/050770.png', 'https://media.retroachievements.org/Images/000556.png', 'https://media.retroachievements.org/Images/000553.png', 'https://media.retroachievements.org/Images/042715.png', 4.4),
  (51, 1373, 'RoboCop Versus The Terminator', 'Genesis/Mega Drive', 1, 3378, 3378, 3378, 32, 0, NULL, 'Virgin Interactive', 'Virgin Interactive', '1994-01-01', 'RoboCop Versus The Terminator is a run and gun game released for the Sega Genesis, Super Nintendo Entertainment System, Master System, and Game Gear in 1993, with a port to the Game Boy in 1994. It is based on the 1992 four-issue comic book mini-series of the same name, which is a crossover between the RoboCop and Terminator franchises. Despite their likenesses being shown on packaging, the actors who portrayed the titular characters did not reprise their roles in this game.', 'https://media.retroachievements.org/Images/077449.png', 'https://media.retroachievements.org/Images/009175.png', 'https://media.retroachievements.org/Images/009172.png', 'https://media.retroachievements.org/Images/009173.png', 4.4),
  (52, 140, 'Wonder Boy in Monster World', 'Genesis/Mega Drive', 1, 3365, 3365, 3365, 49, 0, 'Metroidvania', 'Westone', 'Sega', '1991-10-25', 'Wonder Boy in Monster World, known in Japan as Wonder Boy V: Monster World III, is a side-scrolling action role-playing game originally developed by Westone and published by Sega for the Mega Drive/Genesis in 1991. It is the fifth game in the Wonder Boy series and the third game in the Monster World sub-series, following Wonder Boy in Monster Land and Wonder Boy III: The Dragon''s Trap.', 'https://media.retroachievements.org/Images/034382.png', 'https://media.retroachievements.org/Images/001400.png', 'https://media.retroachievements.org/Images/001399.png', 'https://media.retroachievements.org/Images/001401.png', 4.4),
  (53, 14, 'Alien 3', 'Genesis/Mega Drive', 1, 3233, 3233, 3233, 44, 0, NULL, NULL, 'Acclaim', '1992-06-09', 'Alien 3 (stylized as ALIEN3) is a 1992 American science fiction horror film directed by David Fincher and written by David Giler, Walter Hill, and Larry Ferguson, from a story by Vincent Ward. Starring Sigourney Weaver reprising her role as Ellen Ripley, it is the third installment of the Alien franchise.', 'https://media.retroachievements.org/Images/055716.png', 'https://media.retroachievements.org/Images/051921.png', 'https://media.retroachievements.org/Images/001065.png', 'https://media.retroachievements.org/Images/001066.png', 4.4),
  (54, 82, 'Road Rash', 'Genesis/Mega Drive', 1, 3223, 3223, 3223, 24, 0, 'Arcade Racing', 'Electronic Arts', 'Electronic Arts', '1991-01-01', 'Road Rash is a motorcycle racing video game series by Electronic Arts in which the player participates in violent, illegal street races. The series started on the Sega Genesis/Mega Drive and was released on various other systems over the years. The game''s title is based on the slang term for the severe abrasive injuries that can occur in a motorcycle fall where skin comes into contact with the ground at high speed.', 'https://media.retroachievements.org/Images/077797.png', 'https://media.retroachievements.org/Images/001174.png', 'https://media.retroachievements.org/Images/001170.png', 'https://media.retroachievements.org/Images/001171.png', 4.4),
  (55, 22, 'ToeJam & Earl', 'Genesis/Mega Drive', 1, 3150, 3150, 3150, 56, 0, 'Roguelike', NULL, 'Sega', '1991-10-01', 'ToeJam & Earl is a 1991 action video game developed by Johnson Voorsanger Productions and published by Sega for the Genesis console. It centers on ToeJam and Earl—alien rappers who have crash-landed on Earth—as they attempt to escape the planet, players assume the role of either character and collect pieces of their wrecked spacecraft. It references and parodies 1980s and early-''90s urban culture and is set to a funk soundtrack. ToeJam & Earl''s design was heavily influenced by the role-playing video game Rogue (1980) and derived various features from the game, such as the random generation of levels and items. As such, ToeJam & Earl is often considered to be an example of a roguelike game.', 'https://media.retroachievements.org/Images/107617.png', 'https://media.retroachievements.org/Images/051939.png', 'https://media.retroachievements.org/Images/001217.png', 'https://media.retroachievements.org/Images/001218.png', 4.3),
  (56, 109, 'After Burner II', 'Genesis/Mega Drive', 1, 3092, 3092, 3092, 25, 0, NULL, 'Sega', 'Sega', '1990-03-23', 'After Burner II is an combat flight simulator released as an arcade video game by Sega in 1987. It is the second game in the After Burner series, and was released for the Sega X Board arcade system. In the game, players fly an F-14 Tomcat jet fighter, gunning down enemies while avoiding incoming fire. After Burner II came both a standard arcade cabinet and a servo actuated, sit-down motion simulator version which moved according to the motion of the plane onscreen. The cockpit would bank in the same direction the on-screen aircraft was banking. It is an updated version of After Burner, with the addition of throttle controls. It was a commercial success, becoming Japan''s highest-grossing arcade game of 1988.', 'https://media.retroachievements.org/Images/038433.png', 'https://media.retroachievements.org/Images/000271.png', 'https://media.retroachievements.org/Images/000268.png', 'https://media.retroachievements.org/Images/000269.png', 4.3),
  (57, 2182, 'Earthworm Jim 2', 'Genesis/Mega Drive', 1, 2989, 2989, 2989, 55, 0, NULL, 'Shiny Entertainment', 'Virgin Interactive', '1995-11-15', 'Earthworm Jim 2 is a 1995 run and gun platform game. It is the sequel to Earthworm Jim, and the second and final game in the Earthworm Jim series developed by original creators Doug TenNapel, David Perry, and Shiny Entertainment. It was released in late 1995 and early 1996 depending on the region and video game console, initially for the Sega Genesis and Super Nintendo Entertainment System, before being ported to other platforms.', 'https://media.retroachievements.org/Images/118354.png', 'https://media.retroachievements.org/Images/001525.png', 'https://media.retroachievements.org/Images/001523.png', 'https://media.retroachievements.org/Images/001524.png', 4.3),
  (58, 34, 'Rocket Knight Adventures', 'Genesis/Mega Drive', 1, 2958, 2958, 2958, 36, 0, '2D Platforming', 'Konami', 'Konami', '1993-01-01', 'Rocket Knight Adventures is a 1993 platform game developed and published by Konami for the Sega Genesis. The player controls Sparkster, a possum knight who wields a rocket pack and sword, who battles the evil Devotindos Empire.', 'https://media.retroachievements.org/Images/058017.png', 'https://media.retroachievements.org/Images/001184.png', 'https://media.retroachievements.org/Images/001181.png', 'https://media.retroachievements.org/Images/001182.png', 4.3),
  (59, 6, 'Desert Strike: Return to the Gulf', 'Genesis/Mega Drive', 1, 2948, 2948, 2948, 27, 0, NULL, NULL, NULL, '1992-03-01', 'Desert Strike: Return to the Gulf is a shoot ''em up video game released by Electronic Arts (EA) in 1992 for the Sega Genesis. The game was released on several other formats such as the Super Nintendo Entertainment System, including a much upgraded version for the Amiga home computer. The game was inspired by the Gulf War and depicts a conflict between an insane Middle Eastern dictator, General Kilbaba, and the United States. The player controls an Apache helicopter and attempts to destroy enemy weapons and installations, rescue hostages and capture enemy personnel, while managing supplies of fuel and ammunition.', 'https://media.retroachievements.org/Images/062615.png', 'https://media.retroachievements.org/Images/051874.png', 'https://media.retroachievements.org/Images/001106.png', 'https://media.retroachievements.org/Images/001107.png', 4.3),
  (60, 88, 'Golden Axe III', 'Genesis/Mega Drive', 1, 2945, 2945, 2945, 31, 0, 'Beat ''em Up', 'Sega', 'Sega', '1993-06-25', 'Golden Axe III is a 1993 beat ''em up game developed and published by Sega for the Sega Genesis. Originally exclusive to Japan, it was made available in North America via the Sega Channel online service in 1995. In this sequel to Golden Axe II, the player controls one of four warriors as they attempt to defeat the evil Damud Hellstrike, who has stolen the Golden Axe and kidnapped the princess of Yuria. Much like its predecessors, the game is based around side-scrolling levels where the player defeats enemies with their melee weapon or fists, while riding creatures known as Bizarrians, or through elemental magic. Several new offensive and defensive moves, like blocking and projectile attacks, can also be used.', 'https://media.retroachievements.org/Images/123486.png', 'https://media.retroachievements.org/Images/000308.png', 'https://media.retroachievements.org/Images/000309.png', 'https://media.retroachievements.org/Images/000311.png', 4.3),
  (61, 116, 'Mega Man: The Wily Wars', 'Genesis/Mega Drive', 1, 2816, 2816, 2816, 214, 0, '2D Platforming', 'Capcom', 'Capcom', '1994-10-21', 'Mega Man: The Wily Wars is a 1994 platform game compilation developed by Minakuchi Engineering and published by Capcom for the Sega Genesis; the compilation features remakes of the first three Mega Man games which were originally released on the Nintendo Entertainment System, alongside a new game called Wily Tower, only unlockable with a completed save file.', 'https://media.retroachievements.org/Images/120056.png', 'https://media.retroachievements.org/Images/002729.png', 'https://media.retroachievements.org/Images/002727.png', 'https://media.retroachievements.org/Images/002728.png', 4.3),
  (62, 16, 'Super Hang-On', 'Genesis/Mega Drive', 1, 2763, 2763, 2763, 21, 0, NULL, NULL, NULL, '1989-10-06', 'Super Hang-On is a 1987 racing video game developed and published by Sega for arcades. It is the sequel to 1985''s Hang-On, and uses a simulated motorcycle arcade cabinet, like the original game. An updated version was released for arcades as Limited Edition Hang-On in 1991.', 'https://media.retroachievements.org/Images/000860.png', 'https://media.retroachievements.org/Images/051933.png', 'https://media.retroachievements.org/Images/000712.png', 'https://media.retroachievements.org/Images/000713.png', 4.3),
  (63, 12, 'The Addams Family', 'Genesis/Mega Drive', 1, 2629, 2629, 2629, 69, 0, NULL, NULL, NULL, '1993-10-01', 'The Addams Family is a fictional family created by American cartoonist Charles Addams. The Addams are an eccentric old-money clan who delight in the macabre and the grotesque and are seemingly unaware or unconcerned that other people find them bizarre or frightening. The Addams'' view in seeing their family life and interests as normal was a basis for the satire and comedy. They originally appeared in a series of 150 standalone single-panel comics, about half of which were originally published in The New Yorker between 1938 and their creator''s death in 1988. They have since appeared in other media, such as television, film, video games, comic books, a musical, and merchandise.', 'https://media.retroachievements.org/Images/099515.png', 'https://media.retroachievements.org/Images/051919.png', 'https://media.retroachievements.org/Images/001049.png', 'https://media.retroachievements.org/Images/001050.png', 4.3),
  (64, 294, 'Mega Turrican', 'Genesis/Mega Drive', 1, 2625, 2625, 2625, 24, 0, NULL, 'Factor 5', 'Sony Imagesoft', '1994-06-07', 'Mega Turrican is a run and gun video game developed by Factor 5 in 1993 and published by Data East in 1994. Part of the Turrican series, it was released for the Mega Drive/Genesis, and later followed by an Amiga port converted by Kaiko and Neon Studios under the title of Turrican 3: Payment Day. Despite not being the original, the Amiga version was the one that was first commercially released in 1993, published by Rainbow Arts in Germany and Renegade in the rest of Europe. The Mega Drive version did not have a publisher and stayed unreleased from spring 1993 until 1994, when Data East took over its worldwide distribution. Data East itself released the game in North America, and contracted Sony Imagesoft for the game''s distribution in Europe.', 'https://media.retroachievements.org/Images/076399.png', 'https://media.retroachievements.org/Images/000351.png', 'https://media.retroachievements.org/Images/000347.png', 'https://media.retroachievements.org/Images/000348.png', 4.3),
  (65, 16210, 'Bare Knuckle III', 'Genesis/Mega Drive', 1, 2612, 2612, 2612, 48, 0, 'Beat ''em Up', 'Sega', 'Sega', '1994-03-01', 'Streets of Rage 3 is a 1994 beat ''em up game developed and published by Sega for the Genesis. It is the third installment of the Streets of Rage series and the last game in the original trilogy. The game includes several changes over Streets of Rage and Streets of Rage 2, such as a more complex plot, inclusion of character dialogue, longer levels, more in-depth scenarios and faster gameplay. Weapons can be integrated with unique moves with certain characters, hidden characters were added, and a few cutscenes were included to give the story greater depth.', 'https://media.retroachievements.org/Images/110828.png', 'https://media.retroachievements.org/Images/032984.png', 'https://media.retroachievements.org/Images/032981.png', 'https://media.retroachievements.org/Images/032982.png', 4.3),
  (66, 180, 'Battletoads and Double Dragon: The Ultimate Team', 'Genesis/Mega Drive', 1, 2482, 2482, 2482, 21, 0, 'Beat ''em Up', 'Rare', 'Tradewest', '1993-01-01', 'Battletoads/Double Dragon is a 1993 beat ''em up developed by Rare and published by Tradewest. It was originally released for the Nintendo Entertainment System and later ported to the Mega Drive/Genesis, Super NES, and Game Boy. The SNES version was released on the Nintendo Classics service in September 2024; it was the game''s first re-release as it was not released on the Rare Replay collection.', 'https://media.retroachievements.org/Images/053395.png', 'https://media.retroachievements.org/Images/001080.png', 'https://media.retroachievements.org/Images/001077.png', 'https://media.retroachievements.org/Images/001078.png', 4.3),
  (67, 36, 'Double Dragon', 'Genesis/Mega Drive', 1, 2455, 2455, 2455, 15, 0, 'Beat ''em Up', 'Technōs Japan', 'Taito', '1993-01-01', 'Double Dragon  is a beat ''em up video game series originally developed and published by Technōs Japan. It began with the release of the arcade game Double Dragon in 1987. The series features twin martial artists, Billy and Jimmy Lee, as they fight against various adversaries and rivals.', 'https://media.retroachievements.org/Images/055048.png', 'https://media.retroachievements.org/Images/050394.png', 'https://media.retroachievements.org/Images/004167.png', 'https://media.retroachievements.org/Images/000336.png', 4.3),
  (68, 119, 'Road Rash II', 'Genesis/Mega Drive', 1, 2415, 2415, 2415, 50, 0, 'Arcade racing', 'Electronic Arts', 'Electronic Arts', '1993-01-01', 'Road Rash is a motorcycle racing video game series by Electronic Arts in which the player participates in violent, illegal street races. The series started on the Sega Genesis/Mega Drive and was released on various other systems over the years. The game''s title is based on the slang term for the severe abrasive injuries that can occur in a motorcycle fall where skin comes into contact with the ground at high speed.', 'https://media.retroachievements.org/Images/006316.png', 'https://media.retroachievements.org/Images/001165.png', 'https://media.retroachievements.org/Images/001179.png', 'https://media.retroachievements.org/Images/001164.png', 4.3),
  (69, 2235, '~Hack~ Sonic the Hedgehog: Classic Heroes', 'Genesis/Mega Drive', 1, 2379, 2379, 2379, 42, 0, '2D Platforming', 'Flamewing, ColinC10', 'Hack - Sonic the Hedgehog 2', '2012-07-20', 'Sonic the Hedgehog is a Japanese video game series and media franchise created by the Japanese developers Yuji Naka, Naoto Ohshima, and Hirokazu Yasuhara for Sega. The franchise follows Sonic, an anthropomorphic blue hedgehog with supersonic speed, who battles the mad scientist Doctor Eggman and his robot army. The main Sonic the Hedgehog games are platformers mostly developed by Sonic Team; other games, developed by various studios, include spin-offs in the racing, fighting, party and sports genres. The franchise also incorporates printed media, animations, films, and merchandise.', 'https://media.retroachievements.org/Images/123772.png', 'https://media.retroachievements.org/Images/019963.png', 'https://media.retroachievements.org/Images/115472.png', 'https://media.retroachievements.org/Images/111810.png', 4.3),
  (70, 6718, 'Barney''s Hide and Seek Game', 'Genesis/Mega Drive', 1, 2352, 2352, 2352, 17, 0, 'Educational, 2D Platforming', 'Realtime Associates', 'Sega', '1993-06-01', 'Barney''s Hide & Seek Game is a 1993 licensed edutainment video game developed by Realtime Associates and published by Sega for the Sega Genesis exclusivly in North America. It was based on the children''s television series Barney & Friends. Educational concepts taught in the game include counting, matching, and problem solving. There is a self-play feature that guides the player to the objective without input from the player.', 'https://media.retroachievements.org/Images/042059.png', 'https://media.retroachievements.org/Images/015820.png', 'https://media.retroachievements.org/Images/015818.png', 'https://media.retroachievements.org/Images/015819.png', 4.3),
  (71, 4726, 'Trouble Shooter', 'Genesis/Mega Drive', 1, 2311, 2311, 2311, 27, 0, 'Shoot ''em Up', 'Vic Tokai', 'Vic Tokai', '1991-01-01', 'Trouble Shooter, originally released in Japan as Battle Mania, is a horizontally scrolling shooter developed and published by Vic Tokai for the Mega Drive/Genesis. It was released in November 1991 in North America and March 6, 1992 in Japan. It was directed by designer Fujito Takayan Takada, who at first was primarily responsible for every aspect of the game''s development due to a lack of support from Vic Tokai. Over time, however, more people joined the project, and he took on a supervisory role for much of the game''s design.', 'https://media.retroachievements.org/Images/078313.png', 'https://media.retroachievements.org/Images/048580.png', 'https://media.retroachievements.org/Images/048581.png', 'https://media.retroachievements.org/Images/002367.png', 4.3),
  (72, 65, 'Shining Force', 'Genesis/Mega Drive', 1, 2299, 2299, 2299, 70, 0, 'Tactical RPG', 'Camelot Software Planning', 'Sega', '1992-03-20', 'Shining Force: The Legacy of Great Intention, commonly referred to as Shining Force, is a 1992 turn-based tactical role-playing game developed by Climax Entertainment and Sonic! Software Planning and published by Sega for the Sega Genesis. It is the second entry of the Shining series, following 1991''s Shining in the Darkness. While primarily a traditional fantasy-themed game, it contains some science fiction elements.', 'https://media.retroachievements.org/Images/067488.png', 'https://media.retroachievements.org/Images/004187.png', 'https://media.retroachievements.org/Images/004188.png', 'https://media.retroachievements.org/Images/004189.png', 4.3),
  (73, 3108, 'Battle Mania Daiginjou', 'Genesis/Mega Drive', 1, 2223, 2223, 2223, 35, 0, 'Shoot ''em Up', 'Vic Tokai', 'Vic Tokai', '1993-12-24', 'Battle Mania Daiginjō is a 1993 horizontally scrolling shooter developed and published by Vic Tokai for the Mega Drive. It serves as a sequel to the original Battle Mania, which was released in North America under the title Trouble Shooter. Unlike the original Battle Mania, Daginjō was released exclusively for the Japanese and South Korean markets.', 'https://media.retroachievements.org/Images/119819.png', 'https://media.retroachievements.org/Images/002380.png', 'https://media.retroachievements.org/Images/070602.png', 'https://media.retroachievements.org/Images/002378.png', 4.3),
  (74, 156, 'Boogerman: A Pick and Flick Adventure', 'Genesis/Mega Drive', 1, 2128, 2128, 2128, 30, 0, '2D Platforming', 'Interplay Entertainment', 'Interplay Entertainment', '1994-11-18', 'Boogerman: A Pick and Flick Adventure is a 2D platform video game created by Interplay Productions and released for the Sega Genesis in 1994 and on the Super NES in 1995. The Genesis version was also released on the Wii Virtual Console in North America on November 24, 2008 and in Europe on December 12, 2008. The game''s lead character also appears as a playable character and the rival of Earthworm Jim in Interplay''s ClayFighter 63⅓.', 'https://media.retroachievements.org/Images/113925.png', 'https://media.retroachievements.org/Images/026861.png', 'https://media.retroachievements.org/Images/020615.png', 'https://media.retroachievements.org/Images/020616.png', 4.3),
  (75, 50, 'Phantasy Star IV: The End of the Millennium', 'Genesis/Mega Drive', 1, 2105, 2105, 2105, 93, 0, NULL, 'Sega', 'Sega', '1993-12-17', 'Phantasy Star IV: The End of the Millennium is a 1993 role-playing video game developed and published by Sega for the Sega Genesis. The fourth main installment in the Phantasy Star series, it is the final title in the original tetralogy and is currently the last traditional role-playing game in the franchise. The game''s plot follows the hunters Alys and Chaz, as well as their traveling party, attempting to stop an ecological crisis from destroying their solar system. Phantasy Star IV kept many of the gameplay elements of the previous game, including turn-based battles, overhead exploration, and magic spells. It received mixed reviews upon its release but now it is widely considered the greatest role-playing game ever made for the Sega Genesis and regarded as one of the greatest video games of all time.', 'https://media.retroachievements.org/Images/045807.png', 'https://media.retroachievements.org/Images/000642.png', 'https://media.retroachievements.org/Images/000639.png', 'https://media.retroachievements.org/Images/000640.png', 4.3),
  (76, 221, 'Dynamite Headdy', 'Genesis/Mega Drive', 1, 2088, 2088, 2088, 39, 0, '2D Platforming', 'Treasure', 'Sega', '1994-09-01', 'Ristar is a 1995 platform game developed and published by Sega for the Sega Genesis. The game stars an anthropomorphic cartoon star who uses his hands and long, stretchable arms to both move and fight enemies. Reception for the game was generally positive, but the game''s initial release was overshadowed due to the imminent ending of the Genesis''s lifecycle and the succession of the Sega Saturn and other fifth generation video game consoles.', 'https://media.retroachievements.org/Images/117781.png', 'https://media.retroachievements.org/Images/003528.png', 'https://media.retroachievements.org/Images/002798.png', 'https://media.retroachievements.org/Images/002799.png', 4.3),
  (77, 10229, 'Street Fighter II: Special Champion Edition', 'Genesis/Mega Drive', 1, 2079, 2079, 2079, 26, 0, '2D Fighting', 'Capcom', 'Capcom', '1993-09-18', 'Street Fighter II: Champion Edition, released as Street Fighter II Dash in Japan, is a 1992 fighting game developed and published by Capcom for arcades. It is the first of several updated versions of Street Fighter II (1991), and part of the Street Fighter series. The main changes are the addition of the four grand masters as playable characters and mirror matches. The fighting techniques of the eight main characters from the original game were further balanced for competitive play.', 'https://media.retroachievements.org/Images/115806.png', 'https://media.retroachievements.org/Images/050810.png', 'https://media.retroachievements.org/Images/014415.png', 'https://media.retroachievements.org/Images/014416.png', 4.3),
  (78, 295, 'Bishoujo Senshi Sailor Moon', 'Genesis/Mega Drive', 1, 2063, 2063, 2063, 13, 0, 'Beat ''em Up', 'Arc System Works, TNS', 'Ma-Ba', '1994-07-08', 'Sailor Moon  is a Japanese manga series written and illustrated by Naoko Takeuchi. It was originally serialized in Kodansha''s shōjo manga magazine Nakayoshi from 1991 to 1997; the 60 individual chapters and several side stories were compiled into 18 tankōbon volumes. Set in Tokyo in the 1990s, the series follows the adventures of a schoolgirl named Usagi Tsukino as she transforms into the eponymous character to search for a magical artifact, the Legendary Silver Crystal . She leads a group of comrades, the Sailor Soldiers, called Sailor Guardians in later editions, as they battle against villains to prevent the theft of the Silver Crystal and the destruction of the Solar System.', 'https://media.retroachievements.org/Images/068546.png', 'https://media.retroachievements.org/Images/000586.png', 'https://media.retroachievements.org/Images/000583.png', 'https://media.retroachievements.org/Images/000584.png', 4.3),
  (79, 26, 'Cool Spot', 'Genesis/Mega Drive', 1, 2035, 2035, 2035, 40, 0, '2D Platforming', 'Virgin Interactive', 'Virgin Interactive', '1994-02-18', 'Cool Spot is a 1993 platform game developed by Virgin Games for the Sega Genesis, Super Nintendo Entertainment System, Master System, Game Gear, Game Boy, Amiga, and MS-DOS. The title character is Spot, a mascot for the soft drink brand 7 Up. Spot''s appearance in his own video game came at a time when other brand mascots were appearing in their own video games.', 'https://media.retroachievements.org/Images/054362.png', 'https://media.retroachievements.org/Images/051943.png', 'https://media.retroachievements.org/Images/000466.png', 'https://media.retroachievements.org/Images/000467.png', 4.2),
  (80, 4247, 'Elemental Master', 'Genesis/Mega Drive', 1, 2014, 2014, 2014, 45, 0, 'Shoot ''em Up', 'Technosoft | Tecno Soft', 'Renovation Products', '1993-01-01', 'The Sega Genesis, known as the Mega Drive in regions outside of North America, is a 16-bit video game console that was designed and produced by Sega. First released in Japan on October 29, 1988, in North America on August 1989, and in PAL regions in 1990, the Genesis is Sega''s third console and the successor to the Master System. The system supports a library of 881 officially licensed games created both by Sega and a wide array of third-party publishers and delivered on ROM cartridges. It can also play Master System games when the separately sold Power Base Converter is installed. The Sega Genesis also sported numerous peripherals, including the Sega CD and 32X, several network services, and multiple first-party and third-party variations of the console that focused on extending its functionality. The console and its games continue to be popular among fans, collectors, video game music fans, and emulation enthusiasts. Licensed third party re-releases of the console are still being produced, and several indie game developers continue to produce games for it. Many games have also been re-released in compilations for newer consoles and offered for download on various digital distribution services, such as Virtual Console, Xbox Live Arcade, PlayStation Network, and Steam.', 'https://media.retroachievements.org/Images/110097.png', 'https://media.retroachievements.org/Images/004562.png', 'https://media.retroachievements.org/Images/005011.png', 'https://media.retroachievements.org/Images/005019.png', 4.2),
  (81, 4, 'Zero Tolerance', 'Genesis/Mega Drive', 1, 1989, 1989, 1989, 95, 0, 'First-Person Shooter', 'Technopop', 'Accolade', '1994-10-01', 'A zero-tolerance policy is one which imposes a punishment for every infraction of a stated rule. Zero-tolerance policies forbid people in positions of authority from exercising discretion or changing punishments to fit the circumstances subjectively; they are required to impose a predetermined punishment regardless of individual culpability, extenuating circumstances, or history. This predetermined punishment, whether mild or severe, is always meted out.', 'https://media.retroachievements.org/Images/064502.png', 'https://media.retroachievements.org/Images/051873.png', 'https://media.retroachievements.org/Images/001227.png', 'https://media.retroachievements.org/Images/002230.png', 4.2),
  (82, 501, 'DEcapAttack', 'Genesis/Mega Drive', 1, 1984, 1984, 1984, 109, 0, NULL, 'Vic Tokai', 'Sega', '1991-09-01', 'The Sega Genesis, known as the Mega Drive in regions outside of North America, is a 16-bit video game console that was designed and produced by Sega. First released in Japan on October 29, 1988, in North America on August 1989, and in PAL regions in 1990, the Genesis is Sega''s third console and the successor to the Master System. The system supports a library of 881 officially licensed games created both by Sega and a wide array of third-party publishers and delivered on ROM cartridges. It can also play Master System games when the separately sold Power Base Converter is installed. The Sega Genesis also sported numerous peripherals, including the Sega CD and 32X, several network services, and multiple first-party and third-party variations of the console that focused on extending its functionality. The console and its games continue to be popular among fans, collectors, video game music fans, and emulation enthusiasts. Licensed third party re-releases of the console are still being produced, and several indie game developers continue to produce games for it. Many games have also been re-released in compilations for newer consoles and offered for download on various digital distribution services, such as Virtual Console, Xbox Live Arcade, PlayStation Network, and Steam.', 'https://media.retroachievements.org/Images/043814.png', 'https://media.retroachievements.org/Images/000323.png', 'https://media.retroachievements.org/Images/000320.png', 'https://media.retroachievements.org/Images/000321.png', 4.2),
  (83, 170, 'Columns III: Revenge of Columns', 'Genesis/Mega Drive', 1, 1974, 1974, 1974, 45, 0, NULL, 'Minato Giken', 'Vic Tokai', '1993-10-15', 'Columns III: Revenge of Columns  is a puzzle arcade game published by Sega in Japan in 1993 and by Vic Tokai in North America in 1994 as a sequel to Columns II: The Voyage Through Time.', 'https://media.retroachievements.org/Images/121630.png', 'https://media.retroachievements.org/Images/007915.png', 'https://media.retroachievements.org/Images/020629.png', 'https://media.retroachievements.org/Images/020628.png', 4.2),
  (84, 80, 'X-Men 2: Clone Wars', 'Genesis/Mega Drive', 1, 1951, 1951, 1951, 42, 0, 'Beat ''em Up', 'Headgames', 'Sega', '1995-01-01', 'X-Men 2: Clone Wars is a 1995 2D action-platformer video game developed by Headgames and released by Sega of America for the Mega Drive/Genesis as a sequel to the 1993''s X-Men. The game is based on the adventures of the Marvel Comics superhero team, the X-Men. A sequel, titled X-Women, was cancelled.', 'https://media.retroachievements.org/Images/024366.png', 'https://media.retroachievements.org/Images/015001.png', 'https://media.retroachievements.org/Images/009188.png', 'https://media.retroachievements.org/Images/009186.png', 4.2),
  (85, 2367, 'Valis', 'Genesis/Mega Drive', 1, 1932, 1932, 1932, 51, 0, 'Action', 'Telenet Japan', 'Sega', '1991-12-27', 'The Sega Genesis, known as the Mega Drive in regions outside of North America, is a 16-bit video game console that was designed and produced by Sega. First released in Japan on October 29, 1988, in North America on August 1989, and in PAL regions in 1990, the Genesis is Sega''s third console and the successor to the Master System. The system supports a library of 881 officially licensed games created both by Sega and a wide array of third-party publishers and delivered on ROM cartridges. It can also play Master System games when the separately sold Power Base Converter is installed. The Sega Genesis also sported numerous peripherals, including the Sega CD and 32X, several network services, and multiple first-party and third-party variations of the console that focused on extending its functionality. The console and its games continue to be popular among fans, collectors, video game music fans, and emulation enthusiasts. Licensed third party re-releases of the console are still being produced, and several indie game developers continue to produce games for it. Many games have also been re-released in compilations for newer consoles and offered for download on various digital distribution services, such as Virtual Console, Xbox Live Arcade, PlayStation Network, and Steam.', 'https://media.retroachievements.org/Images/042685.png', 'https://media.retroachievements.org/Images/001465.png', 'https://media.retroachievements.org/Images/001462.png', 'https://media.retroachievements.org/Images/001463.png', 4.2),
  (86, 19, 'Ghostbusters', 'Genesis/Mega Drive', 1, 1929, 1929, 1929, 58, 0, '2D Platforming', 'Compile', 'Sega', '1990-06-30', 'Ghostbusters is a 1984 American supernatural comedy film directed by Ivan Reitman and written by Dan Aykroyd and Harold Ramis. It stars Bill Murray, Aykroyd, and Ramis as Peter Venkman, Ray Stantz, and Egon Spengler, three eccentric parapsychologists who start a ghost-catching business in New York City. It also stars Sigourney Weaver and Rick Moranis, and features Annie Potts, Ernie Hudson, and William Atherton in supporting roles.', 'https://media.retroachievements.org/Images/050351.png', 'https://media.retroachievements.org/Images/000847.png', 'https://media.retroachievements.org/Images/050330.png', 'https://media.retroachievements.org/Images/050331.png', 4.2),
  (87, 125, 'Show do Milhão', 'Genesis/Mega Drive', 1, 1926, 1926, 1926, 21, 0, 'Game Show', 'Tectoy', 'Tectoy', '2001-01-01', 'The Sega Genesis, known as the Mega Drive in regions outside of North America, is a 16-bit video game console that was designed and produced by Sega. First released in Japan on October 29, 1988, in North America on August 1989, and in PAL regions in 1990, the Genesis is Sega''s third console and the successor to the Master System. The system supports a library of 881 officially licensed games created both by Sega and a wide array of third-party publishers and delivered on ROM cartridges. It can also play Master System games when the separately sold Power Base Converter is installed. The Sega Genesis also sported numerous peripherals, including the Sega CD and 32X, several network services, and multiple first-party and third-party variations of the console that focused on extending its functionality. The console and its games continue to be popular among fans, collectors, video game music fans, and emulation enthusiasts. Licensed third party re-releases of the console are still being produced, and several indie game developers continue to produce games for it. Many games have also been re-released in compilations for newer consoles and offered for download on various digital distribution services, such as Virtual Console, Xbox Live Arcade, PlayStation Network, and Steam.', 'https://media.retroachievements.org/Images/024734.png', 'https://media.retroachievements.org/Images/023478.png', 'https://media.retroachievements.org/Images/014537.png', 'https://media.retroachievements.org/Images/014538.png', 4.2),
  (88, 70, 'Ultimate Mortal Kombat 3', 'Genesis/Mega Drive', 1, 1922, 1922, 1922, 43, 0, '2D Fighting', 'Avalanche Software', 'Acclaim, Williams Entertainment', '1995-01-01', 'Ultimate Mortal Kombat 3 is a 1995 fighting game developed and published by Midway for arcades. Part of the Mortal Kombat series, it is a standalone update of 1995''s earlier Mortal Kombat 3 with an altered gameplay system and some new features, as well as additional characters like the returning favorites Reptile, Kitana, Jade and Scorpion, who were missing from Mortal Kombat 3.', 'https://media.retroachievements.org/Images/105572.png', 'https://media.retroachievements.org/Images/081473.png', 'https://media.retroachievements.org/Images/081475.png', 'https://media.retroachievements.org/Images/081485.png', 4.2),
  (89, 67, 'Splatterhouse 3', 'Genesis/Mega Drive', 1, 1914, 1914, 1914, 32, 0, 'Beat ''em Up', 'Now Production', 'Namco', '1993-03-19', 'Splatterhouse is a 1988 beat ''em up video game developed and published by Namco for Japanese arcades. It was the first in a series of games released in home console and personal computer formats. This game would later spawn the parody Splatterhouse: Wanpaku Graffiti, the sequels Splatterhouse 2, Splatterhouse 3, and the 2010 remake Splatterhouse, with the classic games being added to Namco Museum since 2017.', 'https://media.retroachievements.org/Images/048187.png', 'https://media.retroachievements.org/Images/006036.png', 'https://media.retroachievements.org/Images/006033.png', 'https://media.retroachievements.org/Images/006034.png', 4.2),
  (90, 1438, 'Crusader of Centy', 'Genesis/Mega Drive', 1, 1885, 1885, 1885, 79, 0, 'Action RPG', 'Nex Entertainment', 'Atlus', '1994-06-17', 'The Sega Genesis, known as the Mega Drive in regions outside of North America, is a 16-bit video game console that was designed and produced by Sega. First released in Japan on October 29, 1988, in North America on August 1989, and in PAL regions in 1990, the Genesis is Sega''s third console and the successor to the Master System. The system supports a library of 881 officially licensed games created both by Sega and a wide array of third-party publishers and delivered on ROM cartridges. It can also play Master System games when the separately sold Power Base Converter is installed. The Sega Genesis also sported numerous peripherals, including the Sega CD and 32X, several network services, and multiple first-party and third-party variations of the console that focused on extending its functionality. The console and its games continue to be popular among fans, collectors, video game music fans, and emulation enthusiasts. Licensed third party re-releases of the console are still being produced, and several indie game developers continue to produce games for it. Many games have also been re-released in compilations for newer consoles and offered for download on various digital distribution services, such as Virtual Console, Xbox Live Arcade, PlayStation Network, and Steam.', 'https://media.retroachievements.org/Images/064348.png', 'https://media.retroachievements.org/Images/004921.png', 'https://media.retroachievements.org/Images/004946.png', 'https://media.retroachievements.org/Images/004947.png', 4.2),
  (91, 574, 'The Punisher', 'Genesis/Mega Drive', 1, 1815, 1815, 1815, 30, 0, 'Beat ''em Up', 'Capcom', 'Capcom', '1995-02-01', 'The Sega Genesis, known as the Mega Drive in regions outside of North America, is a 16-bit video game console that was designed and produced by Sega. First released in Japan on October 29, 1988, in North America on August 1989, and in PAL regions in 1990, the Genesis is Sega''s third console and the successor to the Master System. The system supports a library of 881 officially licensed games created both by Sega and a wide array of third-party publishers and delivered on ROM cartridges. It can also play Master System games when the separately sold Power Base Converter is installed. The Sega Genesis also sported numerous peripherals, including the Sega CD and 32X, several network services, and multiple first-party and third-party variations of the console that focused on extending its functionality. The console and its games continue to be popular among fans, collectors, video game music fans, and emulation enthusiasts. Licensed third party re-releases of the console are still being produced, and several indie game developers continue to produce games for it. Many games have also been re-released in compilations for newer consoles and offered for download on various digital distribution services, such as Virtual Console, Xbox Live Arcade, PlayStation Network, and Steam.', 'https://media.retroachievements.org/Images/064882.png', 'https://media.retroachievements.org/Images/015476.png', 'https://media.retroachievements.org/Images/009212.png', 'https://media.retroachievements.org/Images/009213.png', 4.2),
  (92, 226, 'Arrow Flash', 'Genesis/Mega Drive', 1, 1787, 1787, 1787, 20, 0, 'Shoot ''em Up', 'ITL', 'Renovation Products, Sega', '1990-10-20', 'Arrow Flash  is a horizontally scrolling shooter video game developed by I.T.L and published by Sega in Japan and Europe and by Renovation Products in the United States for the Mega Drive / Genesis in 1990. The game''s main character pilots a prototype transformable fighter-mecha left from her grandfather to fight against an alien attack on humankind. The game is mostly a horizontal shooter, with one down scrolling stage.', 'https://media.retroachievements.org/Images/049213.png', 'https://media.retroachievements.org/Images/004328.png', 'https://media.retroachievements.org/Images/070037.png', 'https://media.retroachievements.org/Images/004327.png', 4.2),
  (93, 587, 'Zero Wing', 'Genesis/Mega Drive', 1, 1779, 1779, 1779, 34, 0, 'Shoot ''em Up', 'Toaplan', 'Toaplan, Sega', '1991-05-31', 'Zero Wing is a 1989 horizontally scrolling shooter video game developed by Toaplan and published by Namco for Japanese arcades; in North America, it was distributed by Williams Electronics. Controlling the ZIG space fighter craft, players assume the role of protagonist Trent in a last-ditch effort to overthrow the alien space pirate organization CATS. It was the eighth shoot ''em up game from Toaplan, and their fourteenth video game overall.', 'https://media.retroachievements.org/Images/113701.png', 'https://media.retroachievements.org/Images/009226.png', 'https://media.retroachievements.org/Images/103482.png', 'https://media.retroachievements.org/Images/103483.png', 4.2),
  (94, 583, 'Snow Bros.: Nick & Tom', 'Genesis/Mega Drive', 1, 1778, 1778, 1778, 11, 0, '2D Platforming', 'Toaplan', 'Tengen', '1993-05-28', 'Snow Bros. is a 1990 platform video game developed and published by Toaplan for Japanese arcades; it was distributed by Romstar in North America and Europe. Players control snowman twins Nick and Tom as they travel through 50 stages, using snowballs as weapons while navigating obstacles and battling monsters in order to rescue the princesses Puripuri and Puchipuchi. The game was later ported to multiple platforms, each one by different third-party developers and featuring several changes or additions. Versions for various microcomputers were in development, but were never officially released.', 'https://media.retroachievements.org/Images/064810.png', 'https://media.retroachievements.org/Images/117391.png', 'https://media.retroachievements.org/Images/000643.png', 'https://media.retroachievements.org/Images/000644.png', 4.2),
  (95, 60, 'Mortal Kombat II', 'Genesis/Mega Drive', 1, 1777, 1777, 1777, 35, 0, '2D Fighting', 'Probe Entertainment', 'Acclaim', '1994-09-09', 'Mortal Kombat II is a 1993 fighting game developed and published by Midway for arcades. It was later ported to multiple home systems, including MS-DOS, Amiga, Game Boy, Game Gear, Sega Genesis, 32X, Sega Saturn, Super NES, and PlayStation, by Probe Software and Sculptured Software, and published by Acclaim Entertainment.', 'https://media.retroachievements.org/Images/054556.png', 'https://media.retroachievements.org/Images/011786.png', 'https://media.retroachievements.org/Images/011789.png', 'https://media.retroachievements.org/Images/011790.png', 4.2),
  (96, 2364, 'Gargoyles', 'Genesis/Mega Drive', 1, 1747, 1747, 1747, 37, 0, '2D Platforming', 'Disney Interactive Studios', 'Disney Interactive Studios', '1995-05-15', 'The Sega Genesis, known as the Mega Drive in regions outside of North America, is a 16-bit video game console that was designed and produced by Sega. First released in Japan on October 29, 1988, in North America on August 1989, and in PAL regions in 1990, the Genesis is Sega''s third console and the successor to the Master System. The system supports a library of 881 officially licensed games created both by Sega and a wide array of third-party publishers and delivered on ROM cartridges. It can also play Master System games when the separately sold Power Base Converter is installed. The Sega Genesis also sported numerous peripherals, including the Sega CD and 32X, several network services, and multiple first-party and third-party variations of the console that focused on extending its functionality. The console and its games continue to be popular among fans, collectors, video game music fans, and emulation enthusiasts. Licensed third party re-releases of the console are still being produced, and several indie game developers continue to produce games for it. Many games have also been re-released in compilations for newer consoles and offered for download on various digital distribution services, such as Virtual Console, Xbox Live Arcade, PlayStation Network, and Steam.', 'https://media.retroachievements.org/Images/049829.png', 'https://media.retroachievements.org/Images/009332.png', 'https://media.retroachievements.org/Images/017953.png', 'https://media.retroachievements.org/Images/017954.png', 4.2),
  (97, 289, 'Last Battle', 'Genesis/Mega Drive', 1, 1702, 1702, 1702, 30, 0, 'Beat ''em Up', 'Sega', 'Sega', '1989-01-01', 'Last Battle: Legend of the Final Hero is a side-scrolling martial arts beat ''em up released for the Mega Drive/Genesis in 1989 by Sega. It was one of the six games that were available as part of the Genesis launch lineup in the U.S. The Japanese version, titled Hokuto no Ken: Shinseikimatsu Kyūseishu Densetsu , is based on the manga and anime series Fist of the North Star. Since the international version did not retain the Hokuto no Ken license, the graphics and characters'' names were altered. It was the second Hokuto no Ken game released by Sega, following the Mark III original, released internationally as Black Belt. Versions for the Commodore 64 and Amiga based upon Last Battle were developed and released by Elite in Europe in 1991.', 'https://media.retroachievements.org/Images/064828.png', 'https://media.retroachievements.org/Images/028720.png', 'https://media.retroachievements.org/Images/001143.png', 'https://media.retroachievements.org/Images/001144.png', 4.2),
  (98, 1404, 'Steel Empire', 'Genesis/Mega Drive', 1, 1702, 1702, 1702, 26, 0, 'Shoot ''em Up', 'HOT B', 'HOT B, Flying Edge', '1992-03-13', 'Steel Empire is a horizontally scrolling shooter released on the Sega Genesis in 1992. Versions for the Game Boy Advance and Nintendo 3DS were released in 2004 and 2014, respectively. The game was released on the Nintendo Switch at the end of July 2025.', 'https://media.retroachievements.org/Images/073608.png', 'https://media.retroachievements.org/Images/000267.png', 'https://media.retroachievements.org/Images/000105.png', 'https://media.retroachievements.org/Images/000106.png', 4.2),
  (99, 4228, 'Devil Crash MD', 'Genesis/Mega Drive', 1, 1667, 1667, 1667, 39, 0, 'Pinball', 'Technosoft | Tecno Soft', 'Tengen', '1991-10-10', 'The Sega Genesis, known as the Mega Drive in regions outside of North America, is a 16-bit video game console that was designed and produced by Sega. First released in Japan on October 29, 1988, in North America on August 1989, and in PAL regions in 1990, the Genesis is Sega''s third console and the successor to the Master System. The system supports a library of 881 officially licensed games created both by Sega and a wide array of third-party publishers and delivered on ROM cartridges. It can also play Master System games when the separately sold Power Base Converter is installed. The Sega Genesis also sported numerous peripherals, including the Sega CD and 32X, several network services, and multiple first-party and third-party variations of the console that focused on extending its functionality. The console and its games continue to be popular among fans, collectors, video game music fans, and emulation enthusiasts. Licensed third party re-releases of the console are still being produced, and several indie game developers continue to produce games for it. Many games have also been re-released in compilations for newer consoles and offered for download on various digital distribution services, such as Virtual Console, Xbox Live Arcade, PlayStation Network, and Steam.', 'https://media.retroachievements.org/Images/061849.png', 'https://media.retroachievements.org/Images/017233.png', 'https://media.retroachievements.org/Images/017232.png', 'https://media.retroachievements.org/Images/017231.png', 4.2),
  (100, 1426, 'Burning Force', 'Genesis/Mega Drive', 1, 1606, 1606, 1606, 40, 0, 'Rail Shooter', 'Namco', 'Namco', '1990-01-01', 'Burning Force is a 1989 third-person shooter arcade game developed and published by Namco in Japan. A home conversion for the Sega Genesis was released worldwide a year later. The player assumes control of the woman space cadet Hiromi Tengenji, a pilot training to become a member of the Space Force, who must complete each level by shooting down enemies with her airbike and avoiding projectiles. Gameplay is similar to Space Harrier, featuring a fixed camera position behind the player and having similar mechanics. It runs on the Namco System 2 arcade hardware.', 'https://media.retroachievements.org/Images/033988.png', 'https://media.retroachievements.org/Images/008388.png', 'https://media.retroachievements.org/Images/008383.png', 'https://media.retroachievements.org/Images/008384.png', 4.2),
  (101, 15387, '~Homebrew~ Xeno Crisis', 'Genesis/Mega Drive', 1, 1595, 1595, 1595, 54, 0, 'Twin Stick Shooter', 'Bitmap Bureau', 'Homebrew - Genesis/Mega Drive', '2019-10-28', 'Xeno Crisis is a 2019 multidirectional shooter homebrew video game developed and published by Bitmap Bureau for the Sega Mega Drive/Genesis, Linux, macOS, Microsoft Windows, Nintendo Switch, PlayStation 4, and Xbox One. It was later ported to Dreamcast, PlayStation Vita, Neo Geo, Neo Geo CD, Nintendo 64, GameCube, Super Nintendo Entertainment System, and Game Boy Advance. The premise takes place in Outpost 88, a scientific research facility overrun by aliens. The facility sent a distress signal, leading Commander Darius dispatching space marines John Marsh and Sarah Ridley to confront the aliens. Gameplay revolves around players defeating enemies, rescuing survivors, collecting in-game currency for upgrades, and facing against bosses.', 'https://media.retroachievements.org/Images/043219.png', 'https://media.retroachievements.org/Images/043220.png', 'https://media.retroachievements.org/Images/043217.png', 'https://media.retroachievements.org/Images/043218.png', 4.2),
  (102, 59, 'Flicky', 'Genesis/Mega Drive', 1, 1591, 1591, 1591, 20, 0, NULL, 'Sega', 'Sega', '1991-01-01', 'Flicky is a platform game developed by Sega and released as an arcade video game in May 1984. It was licensed to Bally Midway for distribution in the United States. In Flicky, the player controls the eponymous blue bird and must gather all the small birds called Chirps in each round and bring them safely to the exit. There are cat and lizard enemies which can disperse the Chirps and kill the player, but Flicky can use items on the playing field to protect herself and the Chirps from danger.', 'https://media.retroachievements.org/Images/110362.png', 'https://media.retroachievements.org/Images/111743.png', 'https://media.retroachievements.org/Images/000767.png', 'https://media.retroachievements.org/Images/000768.png', 4.2),
  (103, 4123, 'Bonanza Bros.', 'Genesis/Mega Drive', 1, 1566, 1566, 1566, 27, 0, 'Stealth', 'Sega', 'Sega', '1991-05-17', 'Bonanza Bros. is a 3D-style, 2D side-scrolling stealth action game developed and released by Sega in 1990. It is one of the earliest arcade games powered by the Sega System 24 arcade system board. It was ported to various home systems, including the Mega Drive/Genesis, Master System, PC-Engine/TurboGrafx-CD, and several home computers.', 'https://media.retroachievements.org/Images/064552.png', 'https://media.retroachievements.org/Images/001977.png', 'https://media.retroachievements.org/Images/001974.png', 'https://media.retroachievements.org/Images/001975.png', 4.2),
  (104, 52, 'Super Street Fighter II: The New Challengers', 'Genesis/Mega Drive', 1, 1558, 1558, 1558, 24, 0, '2D Fighting', 'Capcom', 'Capcom', '1994-06-25', 'Super Street Fighter II: The New Challengers is a 1993 fighting game developed and published by Capcom for arcades. It is the fourth game in the Street Fighter II sub-series of Street Fighter games, following Street Fighter II Turbo (1992). It refines and balances the existing character roster from the previous versions, and introduces four new characters, including Fei Long, Cammy, T. Hawk, and Dee Jay. It is the first game on Capcom''s CP System II hardware, with more sophisticated graphics and audio over the original CP System hardware used in previous versions of Street Fighter II.', 'https://media.retroachievements.org/Images/119922.png', 'https://media.retroachievements.org/Images/000630.png', 'https://media.retroachievements.org/Images/000627.png', 'https://media.retroachievements.org/Images/000628.png', 4.2),
  (105, 99, 'Fatal Labyrinth', 'Genesis/Mega Drive', 1, 1554, 1554, 1554, 89, 0, 'Roguelike', 'Sega', 'Sega', '1990-11-21', 'Fatal Labyrinth, titled Shi no Meikyuu: Labyrinth of Death (死の迷宮) in Japan, is a 1990 roguelike role-playing video game developed and published by Sega for the Sega Genesis. Originally available exclusively on the Sega Meganet multiplayer gaming service in Japan, it was later released physically in 1991. The game is similar to and shares assets with Dragon Crystal, which was released around that time.', 'https://media.retroachievements.org/Images/046427.png', 'https://media.retroachievements.org/Images/046426.png', 'https://media.retroachievements.org/Images/005217.png', 'https://media.retroachievements.org/Images/005218.png', 4.2),
  (106, 4102, 'Aero the Acro-Bat', 'Genesis/Mega Drive', 1, 1549, 1549, 1549, 85, 0, '2D Platforming', 'Iguana Entertainment', 'Sunsoft', '1993-08-01', 'Aero the Acro-Bat is a 1993 platform video game developed by Iguana Entertainment and published by Sunsoft for the Super Nintendo Entertainment System and Sega Genesis. Aero the Acro-Bat, a red anthropomorphic bat, was created by David Siller. In 2002, Metro 3D released a version of the game for the Game Boy Advance, with a battery back-up. The GBA version was titled Aero The Acro-Bat - Rascal Rival Revenge in Europe and Acrobat Kid in Japan. The Super NES version of the game was released on the Wii''s Virtual Console in the PAL region and North America in July 2010. In 2024, the Super NES version was re-released in August for Nintendo Switch, PlayStation 4, PlayStation 5, Xbox One, and Xbox Series X/S, alongside a new localization in Japanese made by Shinyuden as Aero: Acrobat Kid for the Nintendo Switch users in Japan, while the GBA version was re-released for the same platforms in November.', 'https://media.retroachievements.org/Images/039587.png', 'https://media.retroachievements.org/Images/033704.png', 'https://media.retroachievements.org/Images/033702.png', 'https://media.retroachievements.org/Images/033703.png', 4.2),
  (107, 536, 'Super Smash T.V.', 'Genesis/Mega Drive', 1, 1542, 1542, 1542, 14, 0, 'Twin Stick Shooter', 'Probe Entertainment', 'Flying Edge', '1992-01-01', 'Smash TV is a 1990 twin-stick shooter video game developed and published by Williams Electronics for arcades. It was designed by Eugene Jarvis and programmed by Mark Turmell, with similar gameplay to Jarvis'' earlier game Robotron: 2084 (1982). The Super Nintendo Entertainment System, Sega Genesis, Master System and Game Gear versions are titled Super Smash TV.', 'https://media.retroachievements.org/Images/110681.png', 'https://media.retroachievements.org/Images/001209.png', 'https://media.retroachievements.org/Images/001206.png', 'https://media.retroachievements.org/Images/001207.png', 4.2),
  (108, 290, 'Captain America and the Avengers', 'Genesis/Mega Drive', 1, 1534, 1534, 1534, 11, 0, 'Beat ''em Up', 'Data East', 'Mindscape', '1992-01-01', 'Captain America and the Avengers is a 1991 beat ''em up video game developed and published by Data East for arcades. It features the Avengers team of Marvel Comics characters in a side-scrolling brawling and shooting adventure to defeat the evil Red Skull. The game received ports for the Sega Genesis/Mega Drive, Super Nintendo Entertainment System, Game Boy and Game Gear. A different Data East game was released for the Nintendo Entertainment System.', 'https://media.retroachievements.org/Images/057420.png', 'https://media.retroachievements.org/Images/001093.png', 'https://media.retroachievements.org/Images/001090.png', 'https://media.retroachievements.org/Images/001091.png', 4.2),
  (109, 262, 'Wonder Boy III: Monster Lair', 'Genesis/Mega Drive', 1, 1534, 1534, 1534, 29, 0, NULL, 'Westone', 'Sega', '1990-12-22', 'Wonder Boy III: Monster Lair  is a 1988 platform game developed by Westone and published by Sega for arcades. It is the third game in the Wonder Boy series and the last one released for arcades. A console adaptation was made by Hudson Soft and released in 1989 in Japan for the PC Engine CD-ROM² System; the subsequent North American release on the TurboGrafx-CD dropped the Wonder Boy III title. It was also converted and released by Sega for the Mega Drive in Japan in 1990 and Europe in 1991. Both the TurboGrafx-CD and Mega Drive versions were later re-released for the Wii Virtual Console.', 'https://media.retroachievements.org/Images/055398.png', 'https://media.retroachievements.org/Images/005273.png', 'https://media.retroachievements.org/Images/005271.png', 'https://media.retroachievements.org/Images/005272.png', 4.2),
  (110, 240, 'Truxton', 'Genesis/Mega Drive', 1, 1531, 1531, 1531, 31, 0, 'Shoot ''em Up', 'Toaplan', 'Taito, Romstar, Midway', '1989-12-09', 'Truxton is a 1988 vertically scrolling shooter video game developed by Toaplan and published by Taito for Japanese and European arcades; in North America, it was distributed by Midway. It is set in a future where the Gidans alien race, led by Dogurava, have invaded the fictional planet Borogo. Players assume the role of fighter pilot Tatsuo taking control of the Super Fighter ship on a last-ditch effort to overthrow the alien invaders.', 'https://media.retroachievements.org/Images/078315.png', 'https://media.retroachievements.org/Images/006114.png', 'https://media.retroachievements.org/Images/006112.png', 'https://media.retroachievements.org/Images/006113.png', 4.2),
  (111, 4239, 'DUNE: The Battle for Arrakis', 'Genesis/Mega Drive', 1, 1526, 1526, 1526, 51, 0, 'Real-Time Strategy', NULL, 'Virgin Interactive', '1993-01-01', 'Dune II: The Building of a Dynasty is a 1992 real-time strategy game developed by Westwood Studios and published by Virgin Games. It serves as the sequel to Dune, which came out earlier that same year.', 'https://media.retroachievements.org/Images/062625.png', 'https://media.retroachievements.org/Images/056130.png', 'https://media.retroachievements.org/Images/017959.png', 'https://media.retroachievements.org/Images/017960.png', 4.2),
  (112, 2545, 'Mickey Mania: The Timeless Adventures of Mickey Mouse', 'Genesis/Mega Drive', 1, 1522, 1522, 1522, 20, 0, '2D Platforming', 'Traveller''s Tales', 'Sony Imagesoft', '1994-01-01', 'Mickey Mania: The Timeless Adventures of Mickey Mouse is a 1994 platform video game developed by Traveller''s Tales and published by Sony Imagesoft for the Super NES, Sega Genesis, and Sega CD. In the game, the player controls Mickey Mouse, who must navigate through various side-scrolling levels, each designed and based on classic Mickey Mouse cartoons.', 'https://media.retroachievements.org/Images/087830.png', 'https://media.retroachievements.org/Images/004723.png', 'https://media.retroachievements.org/Images/004724.png', 'https://media.retroachievements.org/Images/004725.png', 4.2),
  (113, 75, 'Shining Force II', 'Genesis/Mega Drive', 1, 1516, 1516, 1516, 98, 0, 'Tactical RPG', 'Climax Entertainment, Camelot Software Planning', 'Sega', '1993-10-01', 'Shining Force II  is a 1993 tactical role-playing game developed by Sonic! Software Planning and published by Sega for the Sega Genesis. Its storyline is not directly connected to the original Shining Force, although the Game Gear title Shining Force Gaiden: Final Conflict links the two games'' plots. The game is much longer than Shining Force, and contains more free roaming. There is no chapter system, so the player can return to previously visited parts of the world. There are also two different ways of promoting certain characters.', 'https://media.retroachievements.org/Images/067487.png', 'https://media.retroachievements.org/Images/000174.png', 'https://media.retroachievements.org/Images/000173.png', 'https://media.retroachievements.org/Images/000090.png', 4.2),
  (114, 2439, 'Gaiares', 'Genesis/Mega Drive', 1, 1504, 1504, 1504, 29, 0, 'Shoot ''em Up', 'Telenet Japan', 'Renovation Products', '1990-01-01', 'Gaiares  is a horizontally scrolling shooter developed by Telenet Japan and published by Renovation for the Sega Genesis in 1990. It was one of the first 8Mb cartridge games on the Genesis. Its title combined Gaia and the suffix less (Res), as the Earth has been lost to pollution in the far future according to the game''s plot.', 'https://media.retroachievements.org/Images/063167.png', 'https://media.retroachievements.org/Images/007912.png', 'https://media.retroachievements.org/Images/029700.png', 'https://media.retroachievements.org/Images/029699.png', 4.2),
  (115, 3684, 'Advanced Busterhawk: Gley Lancer', 'Genesis/Mega Drive', 1, 1495, 1495, 1495, 44, 0, 'Shoot ''em Up', NULL, NULL, '1992-07-17', 'Gley Lancer is a 1992 scrolling shooter video game originally developed by NCS Corporation, published in Japan by Masaya and in South Korea by Samsung for the Sega Mega Drive/Genesis. It was re-released in 2019 by Japanese publisher Columbus Circle. It follows Lucia Cabrock, daughter of Earth Federation Navy admiral Ken, who disappeared while fighting in a war between humans and an unknown alien race that possess the ability to teleport, joined by her friend Teim on a journey to save her father by stealing a starfighter. Controlling the titular fighter ship, the player must fight waves of enemies and bosses, while avoiding collision with their projectiles and other obstacles. The Gley Lancer ship is equipped with two satellites options, whose positions and formations are determined by the player.', 'https://media.retroachievements.org/Images/020895.png', 'https://media.retroachievements.org/Images/050812.png', 'https://media.retroachievements.org/Images/004954.png', 'https://media.retroachievements.org/Images/004968.png', 4.2),
  (116, 205, '~Hack~ Sonic the Hedgehog: Megamix', 'Genesis/Mega Drive', 1, 1490, 1490, 1490, 18, 0, '2D Platforming', 'Team Megamix', 'Hack - Sonic the Hedgehog', '2005-11-15', 'Sonic the Hedgehog is a Japanese video game series and media franchise created by the Japanese developers Yuji Naka, Naoto Ohshima, and Hirokazu Yasuhara for Sega. The franchise follows Sonic, an anthropomorphic blue hedgehog with supersonic speed, who battles the mad scientist Doctor Eggman and his robot army. The main Sonic the Hedgehog games are platformers mostly developed by Sonic Team; other games, developed by various studios, include spin-offs in the racing, fighting, party and sports genres. The franchise also incorporates printed media, animations, films, and merchandise.', 'https://media.retroachievements.org/Images/123774.png', 'https://media.retroachievements.org/Images/003772.png', 'https://media.retroachievements.org/Images/003769.png', 'https://media.retroachievements.org/Images/003770.png', 4.2),
  (117, 166, 'Road Rash 3: Tour de Force', 'Genesis/Mega Drive', 1, 1487, 1487, 1487, 22, 0, 'Racing', 'Electronic Arts', 'Electronic Arts', '1995-05-15', 'The Sega Genesis, known as the Mega Drive in regions outside of North America, is a 16-bit video game console that was designed and produced by Sega. First released in Japan on October 29, 1988, in North America on August 1989, and in PAL regions in 1990, the Genesis is Sega''s third console and the successor to the Master System. The system supports a library of 881 officially licensed games created both by Sega and a wide array of third-party publishers and delivered on ROM cartridges. It can also play Master System games when the separately sold Power Base Converter is installed. The Sega Genesis also sported numerous peripherals, including the Sega CD and 32X, several network services, and multiple first-party and third-party variations of the console that focused on extending its functionality. The console and its games continue to be popular among fans, collectors, video game music fans, and emulation enthusiasts. Licensed third party re-releases of the console are still being produced, and several indie game developers continue to produce games for it. Many games have also been re-released in compilations for newer consoles and offered for download on various digital distribution services, such as Virtual Console, Xbox Live Arcade, PlayStation Network, and Steam.', 'https://media.retroachievements.org/Images/077798.png', 'https://media.retroachievements.org/Images/001178.png', 'https://media.retroachievements.org/Images/001175.png', 'https://media.retroachievements.org/Images/001176.png', 4.2),
  (118, 225, 'Turbo OutRun', 'Genesis/Mega Drive', 1, 1467, 1467, 1467, 24, 0, 'Arcade Racing', NULL, 'Sega', '1992-03-27', 'Turbo OutRun (ターボアウトラン) is a 1989 racing game developed and published by Sega for arcades. A follow-up to 1986''s Out Run, it was released as a dedicated game, as well as an upgrade kit for the original Out Run board. Like its predecessor, Turbo OutRun has players driving a Ferrari, this time a Ferrari F40. Players traverse a set route across the continental United States from New York City to Los Angeles. In addition to a time limit, Turbo OutRun also adds a computer-controlled opponent driving a Porsche 959. The Turbo in the title plays a factor as players can press a button to receive a brief turbo boost of speed. Various power-ups which increase the vehicle''s attributes can be chosen at various stages of the game.', 'https://media.retroachievements.org/Images/072199.png', 'https://media.retroachievements.org/Images/005361.png', 'https://media.retroachievements.org/Images/001803.png', 'https://media.retroachievements.org/Images/001804.png', 4.2),
  (119, 4418, 'Rock n'' Roll Racing', 'Genesis/Mega Drive', 1, 1464, 1464, 1464, 41, 0, 'Racing', 'Silicon & Synapse', 'Interplay Entertainment', '1994-01-01', 'Rock n'' Roll Racing is a vehicular combat-based racing video game developed by Silicon & Synapse and published by Interplay Productions for the Super Nintendo Entertainment System in 1993 and the Mega Drive/Genesis in 1994. The game prominently features a number of popular heavy metal and rock songs in its soundtrack, hence the game''s title. After Silicon & Synapse rebranded into Blizzard Entertainment, a port to the Game Boy Advance was released in 2003. In celebration of the company''s 30th anniversary, a new version titled Definitive Edition alongside emulated re-releases of the original game were re-released for Nintendo Switch, PlayStation 4, Windows, and Xbox One as part of the Blizzard Arcade Collection in February 2021.', 'https://media.retroachievements.org/Images/052342.png', 'https://media.retroachievements.org/Images/006317.png', 'https://media.retroachievements.org/Images/006318.png', 'https://media.retroachievements.org/Images/006326.png', 4.2),
  (120, 143, 'Beyond Oasis', 'Genesis/Mega Drive', 1, 1463, 1463, 1463, 33, 0, 'Action RPG', 'Ancient', 'Sega', '1994-12-09', 'Beyond Oasis is a 1994 action-adventure game developed by Ancient and published by Sega for the Sega Genesis. The game has also been re-released in various emulated collections. A prequel to the game, The Legend of Oasis, was released for the Sega Saturn in 1996.', 'https://media.retroachievements.org/Images/054047.png', 'https://media.retroachievements.org/Images/001085.png', 'https://media.retroachievements.org/Images/001081.png', 'https://media.retroachievements.org/Images/001082.png', 4.2),
  (121, 11185, '~Hack~ Sonic 3D Blast: Director''s Cut', 'Genesis/Mega Drive', 1, 1416, 1416, 1416, 50, 0, '2.5D Platforming', 'Jon Burton', 'Hack - Sonic 3D Blast', '2017-12-23', 'Sonic 3D Blast, known in regions outside North America as Sonic 3D: Flickies'' Island, is a 1996 platform game in the Sonic the Hedgehog series for the Sega Genesis and Sega Saturn. As Sonic the Hedgehog, the player embarks on a journey to save the Flickies, birds enslaved by Doctor Robotnik. The player must guide Sonic through a series of themed levels to collect Flickies and defeat Robotnik. Though it retains game mechanics from prior Sonic games, Sonic 3D Blast is differentiated by its 2D isometric perspective, with pre-rendered 3D models converted into sprites.', 'https://media.retroachievements.org/Images/109358.png', 'https://media.retroachievements.org/Images/015262.png', 'https://media.retroachievements.org/Images/120741.png', 'https://media.retroachievements.org/Images/120742.png', 4.2),
  (122, 178, 'Mighty Morphin Power Rangers', 'Genesis/Mega Drive', 1, 1389, 1389, 1389, 53, 0, '2D Fighting', 'Banpresto', 'Sega', '1994-01-01', 'Mighty Morphin Power Rangers (MMPR) is an American superhero television series produced by Saban Entertainment, which aired from August 28, 1993 to November 27, 1995, on the Fox Kids programming block, lasting three seasons. The series drew elements and stock footage from Super Sentai, a Japanese television series by Toei Company. Each season was inspired by Kyoryu Sentai Zyuranger, Gosei Sentai Dairanger, and Ninja Sentai Kakuranger, respectively. The series is the first entry of the Power Rangers franchise.', 'https://media.retroachievements.org/Images/043830.png', 'https://media.retroachievements.org/Images/010954.png', 'https://media.retroachievements.org/Images/010948.png', 'https://media.retroachievements.org/Images/010949.png', 4.2),
  (123, 4169, 'Bio-Hazard Battle', 'Genesis/Mega Drive', 1, 1386, 1386, 1386, 31, 0, 'Shoot ''em Up', 'Sega', 'Sega', '1992-10-30', 'Bio-Hazard Battle, released in Japan as Crying: Aseimei Sensou , is a 1992 scrolling shooter released for the Sega Genesis and Sega Mega Play arcade platform. It was made available on the Wii''s Virtual Console in February 2007. The game was also re-released on the Steam platform in October 2010. An unreleased X68000 version exists currently under ownership of M2 CEO Naoki Horii.', 'https://media.retroachievements.org/Images/047715.png', 'https://media.retroachievements.org/Images/047716.png', 'https://media.retroachievements.org/Images/047717.png', 'https://media.retroachievements.org/Images/047718.png', 4.2),
  (124, 571, 'Midnight Resistance', 'Genesis/Mega Drive', 1, 1380, 1380, 1380, 27, 0, NULL, 'Data East', 'Sega', '1991-03-29', 'Midnight Resistance  is a side-scrolling run and gun game produced by Data East and released in arcades in 1989. Midnight Resistance is set in a dystopian future where the player controls a member of a resistance movement who goes on a mission to rescue his kidnapped family from a drug kingpin.', 'https://media.retroachievements.org/Images/047930.png', 'https://media.retroachievements.org/Images/047852.png', 'https://media.retroachievements.org/Images/000296.png', 'https://media.retroachievements.org/Images/000297.png', 4.2),
  (125, 46, 'Atomic Runner', 'Genesis/Mega Drive', 1, 1373, 1373, 1373, 33, 0, NULL, 'Data East', 'Data East', '1992-10-16', 'Fighter''s History: Mizoguchi Kiki Ippatsu!! is a 1995 fighting game developed and published by Data East for the Super Famicom. It is the third game in the Fighter''s History series, and the last one published by Data East. The gameplay system is largely unchanged from its predecessor, Karnov''s Revenge, but a few new additions made it to the game, including a new game mode where Mizoguchi is the protagonist, and the new character Chelnov, the hero of Data East''s action game Atomic Runner Chelnov.', 'https://media.retroachievements.org/Images/049849.png', 'https://media.retroachievements.org/Images/088601.png', 'https://media.retroachievements.org/Images/001073.png', 'https://media.retroachievements.org/Images/001074.png', 4.2),
  (126, 302, 'ESWAT: City Under Siege', 'Genesis/Mega Drive', 1, 1368, 1368, 1368, 42, 0, NULL, 'Sega', 'Sega', '1990-10-01', 'ESWAT: City Under Siege, released in Japan as Cyber Police ESWAT , is a 1990 action-platform video game developed and published by Sega for the Sega Genesis and Master System. It is based on the arcade game Cyber Police ESWAT, released a year earlier in 1989. The console game maintains the main characters, plot and some of its enemies from the arcade game, but features some different levels, weapons, and bonuses.', 'https://media.retroachievements.org/Images/009455.png', 'https://media.retroachievements.org/Images/000232.png', 'https://media.retroachievements.org/Images/000229.png', 'https://media.retroachievements.org/Images/000230.png', 4.2),
  (127, 176, 'Marble Madness', 'Genesis/Mega Drive', 1, 1360, 1360, 1360, 19, 0, 'Action/Puzzle', 'Atari, Electronic Arts', 'Electronic Arts', '1991-11-01', 'Marble Madness is a 1984 platform game designed by Mark Cerny and published by Atari Games Inc. for arcades. Set in an isometric perspective, the game tasks the player with guiding a marble through six courses, populated with obstacles and enemies, within a time limit. The player controls the marble by using a trackball. Marble Madness is known for using innovative game technologies: it was Atari''s first to use the Atari System 1 hardware, the first to be programmed in the C programming language, and one of the first to use true stereo sound.', 'https://media.retroachievements.org/Images/044625.png', 'https://media.retroachievements.org/Images/020638.png', 'https://media.retroachievements.org/Images/020636.png', 'https://media.retroachievements.org/Images/020637.png', 4.2),
  (128, 31, 'Fantastic Dizzy', 'Genesis/Mega Drive', 1, 1315, 1315, 1315, 31, 0, 'Action-Adventure, 2D Platforming', 'Codemasters', 'Camerica', '1993-09-21', 'Fantastic Dizzy is a 1991 video game developed by Codemasters. It is part of the Dizzy series. It was published on several platforms, including Mega Drive/Genesis, Master System, Game Gear, Nintendo Entertainment System, Amiga, and MS-DOS.', 'https://media.retroachievements.org/Images/000400.png', 'https://media.retroachievements.org/Images/051951.png', 'https://media.retroachievements.org/Images/105334.png', 'https://media.retroachievements.org/Images/105335.png', 4.1),
  (129, 25, 'Vectorman', 'Genesis/Mega Drive', 1, 1281, 1281, 1281, 47, 0, NULL, 'BlueSky Software', 'Sega', '1995-10-25', 'Vectorman is a 2D action platformer video game developed by BlueSky Software and published by Sega. The game was released for the Sega Genesis in late 1995 in North America and Europe. It was considered a critical and commercial success, achieving its dual goal of retaining interest in the aging Sega Genesis platform in face of the increasingly popular new technology of the next generation of video game consoles and providing competition to industry competitor Nintendo''s popular Donkey Kong Country video game. In subsequent decades, the game was re-released across many Sega-themed video game compilations, and on its own across the Wii Virtual Console, Steam, Sega Forever, and Nintendo Classics digital platforms. A sequel, Vectorman 2, was released in 1996, but despite several abandoned attempts at making a Vectorman 3, no further games have been released.', 'https://media.retroachievements.org/Images/025038.png', 'https://media.retroachievements.org/Images/051942.png', 'https://media.retroachievements.org/Images/000557.png', 'https://media.retroachievements.org/Images/000558.png', 4.1),
  (130, 807, 'Jurassic Park: Rampage Edition', 'Genesis/Mega Drive', 1, 1273, 1273, 1273, 38, 0, 'Action', 'BlueSky Software', 'Sega', '1994-10-01', 'Jurassic Park: Rampage Edition is a 1994 action-platform video game developed by BlueSky Software and published by Sega for the Sega Genesis. It is the sequel to Sega''s previous Jurassic Park video game, based on the 1993 film of the same name and also released for the Genesis. Rampage Edition is a revamped version of its predecessor, featuring similar gameplay with several changes, and a new story that continues from where the previous game ended.', 'https://media.retroachievements.org/Images/022748.png', 'https://media.retroachievements.org/Images/022747.png', 'https://media.retroachievements.org/Images/022746.png', 'https://media.retroachievements.org/Images/022745.png', 4.1),
  (131, 4266, 'The Great Waldo Search', 'Genesis/Mega Drive', 1, 1268, 1268, 1268, 12, 0, 'Hidden Object', 'Radiance Software', 'THQ', '1992-06-01', 'Where''s Wally? The Fantastic Journey is the third Where''s Wally? book, first released in 1989. In the book Wally travels to fantasy lands in search of Wizard Whitebeard''s magical scrolls. The book introduces the second recurring Where''s Wally character, Wizard Whitebeard. Readers are also asked for the first time to find the Wizard''s scrolls.', 'https://media.retroachievements.org/Images/113710.png', 'https://media.retroachievements.org/Images/065255.png', 'https://media.retroachievements.org/Images/112235.png', 'https://media.retroachievements.org/Images/112236.png', 4.1),
  (132, 4237, 'Dragon''s Revenge', 'Genesis/Mega Drive', 1, 1264, 1264, 1264, 25, 0, 'Pinball', 'Tengen', 'Tengen', '1993-12-10', 'Dragon''s Revenge (ドラゴンズ・リベンジ) is a pinball video game by Tengen, released for Sega Genesis in 1993. It is a follow-up to Devil''s Crush, a pinball game set in sword and sorcery scenario, wherein the player has to defeat a dragon and a witch. The game was released to generally positive reviews.', 'https://media.retroachievements.org/Images/027512.png', 'https://media.retroachievements.org/Images/056129.png', 'https://media.retroachievements.org/Images/004817.png', 'https://media.retroachievements.org/Images/004818.png', 4.1),
  (133, 4521, 'Yuu Yuu Hakusho: Makyo Toitsusen', 'Genesis/Mega Drive', 1, 1262, 1262, 1262, 33, 0, '2D Fighting', 'Treasure', 'Treasure, Tectoy', '1994-01-01', 'There are numerous video games based on the YuYu Hakusho manga and anime series created by Yoshihiro Togashi. The Japanese name of the series is romanized as Yū Yū Hakusho and the anime is officially titled Yu Yu Hakusho in North America. The games primarily revolve around the protagonist Yusuke Urameshi, a delinquent junior high school student who is killed while trying to save a young boy from being hit by a car. Yusuke is brought back to life and is promptly given the task of solving cases involving ghosts and demons in the human world.', 'https://media.retroachievements.org/Images/067622.png', 'https://media.retroachievements.org/Images/005853.png', 'https://media.retroachievements.org/Images/005851.png', 'https://media.retroachievements.org/Images/005852.png', 4.1),
  (134, 1360, 'The Flintstones', 'Genesis/Mega Drive', 1, 1255, 1255, 1255, 21, 0, '2D Platforming', 'Taito', 'Taito', '1993-10-22', 'The Flintstones is an American animated sitcom produced by Hanna-Barbera Productions. It was originally broadcast on ABC from September 30, 1960, to April 1, 1966 as the first animated series with a prime-time slot on television, as well as the first animated sitcom. The series takes place in a romanticized Stone Age setting and follows the lives of the titular Fred and Wilma Flintstone and their pet dinosaur, Dino, along with the saber-toothed cat Baby Puss, and Fred and Wilma''s eventual baby girl Pebbles. It also focuses on the Flintstones'' neighbors and best friends Barney and Betty Rubble, and later their adopted baby boy Bamm-Bamm and pet hopparoo (kangaroo) Hoppy.', 'https://media.retroachievements.org/Images/123952.png', 'https://media.retroachievements.org/Images/001131.png', 'https://media.retroachievements.org/Images/010290.png', 'https://media.retroachievements.org/Images/000110.png', 4.1),
  (135, 305, 'Toki: Going Ape Spit', 'Genesis/Mega Drive', 1, 1238, 1238, 1238, 29, 0, '2D Platforming', 'Santos', 'Sega', '1991-01-01', 'The Sega Genesis, known as the Mega Drive in regions outside of North America, is a 16-bit video game console that was designed and produced by Sega. First released in Japan on October 29, 1988, in North America on August 1989, and in PAL regions in 1990, the Genesis is Sega''s third console and the successor to the Master System. The system supports a library of 881 officially licensed games created both by Sega and a wide array of third-party publishers and delivered on ROM cartridges. It can also play Master System games when the separately sold Power Base Converter is installed. The Sega Genesis also sported numerous peripherals, including the Sega CD and 32X, several network services, and multiple first-party and third-party variations of the console that focused on extending its functionality. The console and its games continue to be popular among fans, collectors, video game music fans, and emulation enthusiasts. Licensed third party re-releases of the console are still being produced, and several indie game developers continue to produce games for it. Many games have also been re-released in compilations for newer consoles and offered for download on various digital distribution services, such as Virtual Console, Xbox Live Arcade, PlayStation Network, and Steam.', 'https://media.retroachievements.org/Images/116531.png', 'https://media.retroachievements.org/Images/009930.png', 'https://media.retroachievements.org/Images/020671.png', 'https://media.retroachievements.org/Images/020672.png', 4.1),
  (136, 7682, '~Homebrew~ CrazyBus', 'Genesis/Mega Drive', 1, 1215, 1215, 1215, 13, 0, 'Racing', 'Tom Scripts', 'Devster Specialties', '2005-09-09', 'Crazy Bus is a 2004 unlicensed bus simulator video game. Originally created as a tech demo, it was subsequently put on a ROM cartridge and published by an unauthorized 3rd party for the Sega Genesis. The game was developed by Venezuelan game developer Tom Maneiro under the alias Tom Scripts.', 'https://media.retroachievements.org/Images/089846.png', 'https://media.retroachievements.org/Images/010175.png', 'https://media.retroachievements.org/Images/007933.png', 'https://media.retroachievements.org/Images/007934.png', 4.1),
  (137, 51, 'Bubsy in Claws Encounters of the Furred Kind', 'Genesis/Mega Drive', 1, 1204, 1204, 1204, 20, 0, '2D Platforming', 'Accolade', 'Al Baker & Associates', '1993-07-01', 'Bubsy in: Claws Encounters of the Furred Kind, often shortened to Bubsy, is a 1993 platform game developed and published by Accolade for the Super Nintendo Entertainment System. A port to the Sega Genesis was released months later. It is the first entry in the Bubsy series of video games. The game''s title is a play on words in reference to the film Close Encounters of the Third Kind, with the game revolving around Bubsy defending the planet''s supply of yarn balls from alien invaders.', 'https://media.retroachievements.org/Images/117696.png', 'https://media.retroachievements.org/Images/116809.png', 'https://media.retroachievements.org/Images/103133.png', 'https://media.retroachievements.org/Images/000502.png', 4.1),
  (138, 2348, 'Super Fantasy Zone', 'Genesis/Mega Drive', 1, 1192, 1192, 1192, 45, 0, 'Shoot ''em Up', 'Sunsoft', 'Sega', '1992-01-14', 'Super Fantasy Zone  is a 1992 scrolling shooter video game developed and published by Sunsoft for the Mega Drive. Part of Sega''s Fantasy Zone series, it was released only in Japan and Europe. Players control the character Opa-Opa on his quest to defeat Dark Menon, and the game plays similarly to previous Fantasy Zone entries. The game plays similarly to Defender, where the screen scrolls in the direction that Opa-Opa is going. The player shoots at enemies to defeat them, collecting gold coins that are used to purchase temporary upgrades that improve Opa-Opa''s offensive capabilities and speed, among other things.', 'https://media.retroachievements.org/Images/066090.png', 'https://media.retroachievements.org/Images/001422.png', 'https://media.retroachievements.org/Images/001419.png', 'https://media.retroachievements.org/Images/001420.png', 4.1),
  (139, 4270, 'Frogger', 'Genesis/Mega Drive', 1, 1190, 1190, 1190, 21, 0, 'Arcade', 'Morning Star Multimedia', 'Majesco Entertainment', '1998-01-01', 'Frogger is a 1981 action video game developed by Konami and published by Sega for arcades. It was released in North America by Sega/Gremlin. The object of the game is to direct five frogs to their homes by dodging traffic on a busy road, then crossing a river by jumping on floating logs, turtles, and alligators.', 'https://media.retroachievements.org/Images/073195.png', 'https://media.retroachievements.org/Images/073418.png', 'https://media.retroachievements.org/Images/015124.png', 'https://media.retroachievements.org/Images/015125.png', 4.1),
  (140, 1443, 'Vectorman 2', 'Genesis/Mega Drive', 1, 1188, 1188, 1188, 38, 0, NULL, 'BlueSky Software', 'Sega', '1996-11-08', 'Vectorman 2 is a 1996 action-platform video game developed by BlueSky Software and published by Sega for the Sega Genesis. Released a year after the original Vectorman, the game retains the game''s core gameplay while expanding its mechanics. Multiple attempts to create a Vectorman 3 were proposed to Sega, with none of them coming to fruition.', 'https://media.retroachievements.org/Images/046319.png', 'https://media.retroachievements.org/Images/017479.png', 'https://media.retroachievements.org/Images/017478.png', 'https://media.retroachievements.org/Images/017480.png', 4.1),
  (141, 5902, 'Side Pocket', 'Genesis/Mega Drive', 1, 1171, 1171, 1171, 16, 0, 'Sports - Billiards', 'Data East', 'Data East', '1992-01-01', 'Side Pocket is a pocket billiards simulation released as an arcade video game by Data East in 1986. It was ported to the Nintendo Entertainment System and Game Boy, while an enhanced remake was later released on the Sega Genesis, Super Nintendo Entertainment System, and Game Gear. The game spawned two sequels, as well as arcade spin-off series titled Pocket Gal.', 'https://media.retroachievements.org/Images/077460.png', 'https://media.retroachievements.org/Images/007527.png', 'https://media.retroachievements.org/Images/009224.png', 'https://media.retroachievements.org/Images/009225.png', 4.1),
  (142, 12933, 'Pac-Mania', 'Genesis/Mega Drive', 1, 1168, 1168, 1168, 60, 0, 'Maze Chase', 'Namco', 'Tengen', '1991-01-01', 'Pac-Mania is a 1987 maze video game developed and published by Namco for Japanese arcades; it was licensed to Atari Games for release in North America. In the game, the player controls Pac-Man as he must eat all of the dots while avoiding the colored ghosts that chase him in the maze. Eating large flashing Power Pellets will allow Pac-Man to eat the ghosts for bonus points, which lasts for a short period of time. A new feature to this game allows Pac-Man to jump over the ghosts to evade capture. It is the ninth title in the Pac-Man video game series and was the last one developed for arcades up until the release of Pac-Man Arrangement in 1996. Development was directed by Pac-Man creator Tōru Iwatani.', 'https://media.retroachievements.org/Images/099195.png', 'https://media.retroachievements.org/Images/050647.png', 'https://media.retroachievements.org/Images/050391.png', 'https://media.retroachievements.org/Images/050392.png', 4.1),
  (143, 313, 'The Immortal', 'Genesis/Mega Drive', 1, 1168, 1168, 1168, 19, 0, 'CRPG', 'Electronic Arts', 'Electronic Arts', '1993-08-09', 'The Immortal is an isometric action-adventure game created by Will Harvey and released by Electronic Arts in 1990 for the Apple IIGS. It was ported to the Amiga, Atari ST, MS-DOS, Nintendo Entertainment System, and Genesis. A wizard is attempting to find his mentor in a large and dangerous labyrinth. The game has a high degree of graphic violence.', 'https://media.retroachievements.org/Images/063208.png', 'https://media.retroachievements.org/Images/009928.png', 'https://media.retroachievements.org/Images/009940.png', 'https://media.retroachievements.org/Images/009941.png', 4.1),
  (144, 303, 'Mercs', 'Genesis/Mega Drive', 1, 1141, 1141, 1141, 22, 0, NULL, 'Sega', 'Sega', '1991-09-27', 'Mercs, released as Senjō no Ōkami II in Japan, is a 1990 run and gun video game developed and published by Capcom for arcades. It is a sequel to the 1985 arcade video game Commando. While not as successful as its predecessor, Mercs was well received by critics and was a moderate commercial success. It was followed by Wolf of the Battlefield: Commando 3 in 2008, a downloadable game.', 'https://media.retroachievements.org/Images/064450.png', 'https://media.retroachievements.org/Images/051185.png', 'https://media.retroachievements.org/Images/051184.png', 'https://media.retroachievements.org/Images/051183.png', 4.1),
  (145, 4462, 'Chase H.Q. II', 'Genesis/Mega Drive', 1, 1140, 1140, 1140, 29, 0, 'Racing', 'ITL', 'Taito', '1992-10-23', 'Special Criminal Investigation, also known as S.C.I. for short or as Chase HQ II: Special Criminal Investigation in some home versions, is a 1989 vehicular combat racing game developed and published by Taito for arcades. It is the sequel to the 1988 game Chase H.Q.', 'https://media.retroachievements.org/Images/054933.png', 'https://media.retroachievements.org/Images/054916.png', 'https://media.retroachievements.org/Images/054917.png', 'https://media.retroachievements.org/Images/054918.png', 4.1),
  (146, 1436, 'Phantasy Star II', 'Genesis/Mega Drive', 1, 1134, 1134, 1134, 69, 0, 'Turn-Based RPG', 'Sega', 'Sega', '1990-03-01', 'Phantasy Star II is a science fantasy role-playing video game developed and published by Sega for the Sega Genesis. It was released in Japan in 1989 and North America and Europe in 1990. It was later ported to a variety of different platforms. An updated remake, Phantasy Star Generation 2, was released for the PlayStation 2 in 2005 in Japan.', 'https://media.retroachievements.org/Images/076388.png', 'https://media.retroachievements.org/Images/014323.png', 'https://media.retroachievements.org/Images/007993.png', 'https://media.retroachievements.org/Images/008539.png', 4.1),
  (147, 126, 'Show do Milhão: Volume 2', 'Genesis/Mega Drive', 1, 1130, 1130, 1130, 14, 0, 'Game Show', 'Tectoy', 'Tectoy', '2002-01-01', 'The Sega Genesis, known as the Mega Drive in regions outside of North America, is a 16-bit video game console that was designed and produced by Sega. First released in Japan on October 29, 1988, in North America on August 1989, and in PAL regions in 1990, the Genesis is Sega''s third console and the successor to the Master System. The system supports a library of 881 officially licensed games created both by Sega and a wide array of third-party publishers and delivered on ROM cartridges. It can also play Master System games when the separately sold Power Base Converter is installed. The Sega Genesis also sported numerous peripherals, including the Sega CD and 32X, several network services, and multiple first-party and third-party variations of the console that focused on extending its functionality. The console and its games continue to be popular among fans, collectors, video game music fans, and emulation enthusiasts. Licensed third party re-releases of the console are still being produced, and several indie game developers continue to produce games for it. Many games have also been re-released in compilations for newer consoles and offered for download on various digital distribution services, such as Virtual Console, Xbox Live Arcade, PlayStation Network, and Steam.', 'https://media.retroachievements.org/Images/024873.png', 'https://media.retroachievements.org/Images/044541.png', 'https://media.retroachievements.org/Images/014735.png', 'https://media.retroachievements.org/Images/014736.png', 4.1),
  (148, 349, 'Spider-Man & Venom: Maximum Carnage', 'Genesis/Mega Drive', 1, 1112, 1112, 1112, 29, 0, 'Beat ''em Up', 'Software Creations', 'Acclaim', '1994-09-16', 'Spider-Man and Venom: Maximum Carnage is a 1994 beat ''em up video game developed by Software Creations and published by Acclaim Entertainment and its subsidiary LJN for the Super Nintendo Entertainment System and Sega Genesis. The game, based on the comic book story arc of the same name, features numerous heroes, including Spider-Man, Venom, and their allies from the Marvel Comics fictional universe like Captain America, Black Cat, Iron Fist, Cloak and Dagger, Deathlok, Morbius and Firestar, all teaming up to battle an onslaught of villains led by Carnage, including Shriek, Doppelganger, Demogoblin and Carrion.', 'https://media.retroachievements.org/Images/071510.png', 'https://media.retroachievements.org/Images/071511.png', 'https://media.retroachievements.org/Images/020689.png', 'https://media.retroachievements.org/Images/020690.png', 4.1),
  (149, 230, 'Phelios', 'Genesis/Mega Drive', 1, 1099, 1099, 1099, 50, 0, 'Shoot ''em Up', 'Namco', 'Namco', '1990-07-20', 'Phelios is a 1989 arcade scrolling shooter video game developed and published by Namco exclusively in Japan. Loosely based on elements from Greek mythology, it follows the sun god Apollo, mounted atop the winged horse Pegasus, fighting through various locales as they attempt to rescue the moon goddess Artemis from the titan Typhon. The gameplay is based around a series of vertically scrolling levels, which are split up into sections and contain enemies and bosses that must be dealt with in order to progress. Additionally, players can charge up their shots in order to deal more damage to foes.', 'https://media.retroachievements.org/Images/004945.png', 'https://media.retroachievements.org/Images/095886.png', 'https://media.retroachievements.org/Images/004943.png', 'https://media.retroachievements.org/Images/004944.png', 4.1),
  (150, 4148, 'The Jungle Book', 'Genesis/Mega Drive', 1, 1078, 1078, 1078, 31, 0, '2D Platforming', 'Eurocom, Virgin Interactive', 'Virgin Interactive', '1994-07-01', 'The Jungle Book is an 1894 collection of stories by the English author Rudyard Kipling. Most of the characters are animals such as Shere Khan the tiger and Baloo the bear, though a principal character is the boy or man-cub Mowgli, who is raised in the jungle by wolves. Most stories are set in a forest in India; one place mentioned repeatedly is Seeonee (Seoni), in the central state of Madhya Pradesh.', 'https://media.retroachievements.org/Images/025711.png', 'https://media.retroachievements.org/Images/005207.png', 'https://media.retroachievements.org/Images/005209.png', 'https://media.retroachievements.org/Images/005208.png', 4.1),
  (151, 2268, 'Valis III', 'Genesis/Mega Drive', 1, 1073, 1073, 1073, 43, 0, 'Action', 'Telenet Japan', 'Sega, Renovation', '1991-03-22', 'Valis III is a 1990 action-platform video game originally developed by Laser Soft, published by Telenet Japan and NEC for the TurboGrafx-CD. A Sega Genesis version was released in 1991. It is the third entry in the Valis series. It stars Yuko Asou, a Japanese teenage schoolgirl chosen as the Valis warrior and wielder of the mystical Valis sword after the events of Valis II. King Glames, wielder of the sword Leethus, leads denizens of the dark world to conquer both Vecanti and Earth, seeking refuge for his people amid the destruction of their planet. Together with the demon warrior-maiden Cham and her sister Valna, Yuko must prevent Glames from destroying both worlds. Through the journey, the player explores and searches for items and power-ups while fighting enemies and defeating bosses.', 'https://media.retroachievements.org/Images/039835.png', 'https://media.retroachievements.org/Images/001418.png', 'https://media.retroachievements.org/Images/001415.png', 'https://media.retroachievements.org/Images/001416.png', 4.1),
  (152, 330, 'Wings of Wor', 'Genesis/Mega Drive', 1, 1071, 1071, 1071, 29, 0, 'Shoot ''em Up', 'NCS', 'DreamWorks, Masaya | NCS, Sega', '1991-01-25', 'Cho Aniki  is a Japanese video game series originally developed by Masaya and published by NCS Corp. The first game was released in 1992 for the PC Engine system. The game''s sequels and spin-offs later appeared on the Super Famicom, PlayStation, Sega Saturn, WonderSwan, PlayStation 2 and PlayStation Portable. Mainly consisting of side-scrolling shoot ''em ups in the vein of Gradius, the Cho Aniki series is best known for its homoerotic overtones, wacky humor and vivid, surreal imagery. Most of the games have never seen release outside Japan.', 'https://media.retroachievements.org/Images/055296.png', 'https://media.retroachievements.org/Images/124239.png', 'https://media.retroachievements.org/Images/000343.png', 'https://media.retroachievements.org/Images/000344.png', 4.1),
  (153, 8393, '~Homebrew~ Fix-it Felix Jr.', 'Genesis/Mega Drive', 1, 1062, 1062, 1062, 8, 0, 'Arcade', 'TobiKomi, Airwalk Studios', 'TobiKomi', '2014-03-25', 'The Sega Genesis, known as the Mega Drive outside North America, is a 16-bit fourth generation home video game console developed and sold by Sega. It was Sega''s third console and the successor to the Master System. Sega released it in October 1988 in Japan as the Mega Drive, and in August 1989 in North America as the Genesis. In 1990, it was distributed as the Mega Drive by Virgin Mastertronic in Europe, Ozisoft in Australasia, and Tectoy in Brazil. In South Korea, it was distributed by Samsung Electronics as the Super Gam*Boy and later the Super Aladdin Boy.', 'https://media.retroachievements.org/Images/121539.png', 'https://media.retroachievements.org/Images/010167.png', 'https://media.retroachievements.org/Images/099181.png', 'https://media.retroachievements.org/Images/099182.png', 4.1),
  (154, 33403, '~Homebrew~ Old Towers', 'Genesis/Mega Drive', 1, 1061, 1061, 1061, 16, 0, 'Puzzle Platforming', 'RetroSouls', 'RetroSouls', '2019-02-28', 'Sonic Spinball, also known as Sonic the Hedgehog Spinball, is a 1993 pinball video game developed by Sega Technical Institute and published by Sega for the Sega Genesis. It is a spin-off of the Sonic the Hedgehog series. Players control Sonic the Hedgehog, who must stop Doctor Robotnik from enslaving the population in a giant pinball-like mechanism. The game is set in a series of pinball machine-like environments with Sonic acting as the pinball.', 'https://media.retroachievements.org/Images/110192.png', 'https://media.retroachievements.org/Images/110191.png', 'https://media.retroachievements.org/Images/110171.png', 'https://media.retroachievements.org/Images/110172.png', 4.1),
  (155, 44, 'Air Buster', 'Genesis/Mega Drive', 1, 1029, 1029, 1029, 17, 0, 'Shoot ''em Up', 'Kaneko', 'Namco', '1991-01-31', 'This is a list of cast members of the television series MythBusters on the Discovery Channel. In addition to the core cast members, the MythBusters team includes several honorary MythBusters, and some recurring guests.', 'https://media.retroachievements.org/Images/029533.png', 'https://media.retroachievements.org/Images/056471.png', 'https://media.retroachievements.org/Images/001061.png', 'https://media.retroachievements.org/Images/001062.png', 4.1),
  (156, 317, 'Rolling Thunder 2', 'Genesis/Mega Drive', 1, 1017, 1017, 1017, 24, 0, NULL, 'Namco', 'Namco', '1991-01-01', 'Rolling Thunder 2 is a 1991 run and gun video game developed and published by Namco for arcades. The game is the sequel to 1986''s Rolling Thunder, retaining the same gameplay of its predecessor while adding cooperative gameplay for two players and improved graphics. Unlike the original, which was set in 1968, Rolling Thunder 2 has a more contemporary setting to go with its more futuristic design, as well as an optionally playable female character.', 'https://media.retroachievements.org/Images/054353.png', 'https://media.retroachievements.org/Images/005873.png', 'https://media.retroachievements.org/Images/005871.png', 'https://media.retroachievements.org/Images/005872.png', 4.1),
  (157, 203, 'Toy Story', 'Genesis/Mega Drive', 1, 1013, 1013, 1013, 32, 0, '2D Platforming', 'Traveller''s Tales', 'Disney Interactive Studios', '1995-01-01', 'Toy Story is a 1995 American animated adventure comedy film produced by Pixar Animation Studios for Walt Disney Pictures. The first entirely computer-animated feature film, as well as the first feature film from Pixar, it was directed by John Lasseter and written by Joss Whedon, Andrew Stanton, Joel Cohen, and Alec Sokolow. The film features the voices of Tom Hanks, Tim Allen, Annie Potts, John Ratzenberger, Don Rickles, Wallace Shawn, and Jim Varney. Taking place in a world where toys come to life when humans are not present, Toy Story follows an old-fashioned pullstring cowboy doll named Woody (Hanks), and a modern space cadet action figure, Buzz Lightyear (Allen), as Woody develops jealousy towards Buzz when he becomes their owner Andy''s favorite toy.', 'https://media.retroachievements.org/Images/065387.png', 'https://media.retroachievements.org/Images/015495.png', 'https://media.retroachievements.org/Images/015493.png', 'https://media.retroachievements.org/Images/015494.png', 4.1),
  (158, 29, 'James Pond II - Codename: RoboCod', 'Genesis/Mega Drive', 1, 1009, 1009, 1009, 27, 0, '2D Platforming', 'Vectordean', 'Electronic Arts', '1991-01-01', 'James Pond 2: Codename: RoboCod, also known as Super James Pond on Super NES and Game Boy in North America and Super James Pond 2 in Europe, is a 1991 platform video game. It is the second installment in the James Pond series after James Pond: Underwater Agent and was developed by the same British teams as the original. The title music by Richard Joseph is a marimba-heavy rendition of the RoboCop film theme.', 'https://media.retroachievements.org/Images/108488.png', 'https://media.retroachievements.org/Images/051949.png', 'https://media.retroachievements.org/Images/010853.png', 'https://media.retroachievements.org/Images/010854.png', 4.1),
  (159, 2413, 'Mazin Saga: Mutant Fighter', 'Genesis/Mega Drive', 1, 1002, 1002, 1002, 38, 0, 'Beat ''em Up', 'Almanic | Givro', 'Vic Tokai, Sega', '1993-01-01', 'Mazin Saga: Mutant Fighter is a 1993 hybrid beat ''em up/fighting video game developed by Almanic Corporation, in conjunction with ALU and Team "Saga", and published by Sega for the Sega Genesis/Mega Drive in Japan and Europe and later in North America by Vic Tokai. Based upon Go Nagai''s MazinSaga mecha manga, which is considered a combination of Nagai''s Mazinger and Devilman franchises, players assume the role of Koji Kabuto wielding the Mazinger Z armor to fight against powerful ''Bio Beasts'' led by God Kaiser Hell. Co-directed by Satsuki Mizuno, Takashi Yoneda and "Tommy Bon Bon", the title was created by most of the same team that worked on previous projects at Almanic such as E.V.O.: Search for Eden. It was met with mostly positive reception from critics since its release.', 'https://media.retroachievements.org/Images/064349.png', 'https://media.retroachievements.org/Images/006873.png', 'https://media.retroachievements.org/Images/009064.png', 'https://media.retroachievements.org/Images/009066.png', 4.1),
  (160, 2415, 'McDonald''s Treasure Land Adventure', 'Genesis/Mega Drive', 1, 1001, 1001, 1001, 27, 0, '2D Platforming', 'Treasure', 'Sega, Tectoy', '1993-09-23', 'McDonald''s Treasure Land Adventure is a 1993 platform game developed by Treasure and published by Sega for the Sega Genesis. Based on the McDonald''s fast food restaurant chain, specifically its McDonaldland marketing campaign, players control Ronald McDonald in his efforts to retrieve the missing pieces of a map that lead to the location of a buried treasure from a group of villains. Ronald can defeat enemies by using a magic attack and can latch onto hooks with his scarf to reach higher platforms.', 'https://media.retroachievements.org/Images/106816.png', 'https://media.retroachievements.org/Images/006270.png', 'https://media.retroachievements.org/Images/043060.png', 'https://media.retroachievements.org/Images/043061.png', 4.1),
  (161, 556, 'Ranger-X', 'Genesis/Mega Drive', 1, 979, 979, 979, 20, 0, 'Run & Gun', 'GAU Entertainment', 'Sega', '1993-05-28', 'Ranger X is a side scrolling run and gun video game for the Sega Genesis. Developed by GAU Entertainment and published by Sega, the game was released in 1993.', 'https://media.retroachievements.org/Images/113698.png', 'https://media.retroachievements.org/Images/003954.png', 'https://media.retroachievements.org/Images/003952.png', 'https://media.retroachievements.org/Images/003958.png', 4.1),
  (162, 165, 'Flashback: The Quest for Identity', 'Genesis/Mega Drive', 1, 975, 975, 975, 42, 0, 'Cinematic Platforming', 'Delphine Software International', 'U.S. Gold', '1993-02-20', 'The Sega Genesis, known as the Mega Drive in regions outside of North America, is a 16-bit video game console that was designed and produced by Sega. First released in Japan on October 29, 1988, in North America on August 1989, and in PAL regions in 1990, the Genesis is Sega''s third console and the successor to the Master System. The system supports a library of 881 officially licensed games created both by Sega and a wide array of third-party publishers and delivered on ROM cartridges. It can also play Master System games when the separately sold Power Base Converter is installed. The Sega Genesis also sported numerous peripherals, including the Sega CD and 32X, several network services, and multiple first-party and third-party variations of the console that focused on extending its functionality. The console and its games continue to be popular among fans, collectors, video game music fans, and emulation enthusiasts. Licensed third party re-releases of the console are still being produced, and several indie game developers continue to produce games for it. Many games have also been re-released in compilations for newer consoles and offered for download on various digital distribution services, such as Virtual Console, Xbox Live Arcade, PlayStation Network, and Steam.', 'https://media.retroachievements.org/Images/055707.png', 'https://media.retroachievements.org/Images/008412.png', 'https://media.retroachievements.org/Images/008410.png', 'https://media.retroachievements.org/Images/008411.png', 4.1),
  (163, 4222, 'Dahna: Megami Tanjou', 'Genesis/Mega Drive', 1, 966, 966, 966, 18, 0, 'Action', 'Information Global Service', 'Information Global Service', '1991-12-20', 'Dahna: Megami Tanjō  is a 1991 platform action game developed by and published by IGS for the Mega Drive exclusively in Japan and South Korea. The player controls the woman warrior-esque title character who struggles against the powers of an evil sorceress raiding her village. The story is told through cut scenes as Dahna is helped along the way by various mythical beasts.', 'https://media.retroachievements.org/Images/006212.png', 'https://media.retroachievements.org/Images/006211.png', 'https://media.retroachievements.org/Images/006208.png', 'https://media.retroachievements.org/Images/006210.png', 4.1),
  (164, 13943, '~Homebrew~ Cave Story MD', 'Genesis/Mega Drive', 1, 962, 962, 962, 84, 0, '2D Platforming', 'andwn', 'andwn', '2020-07-29', 'M2 Co., Ltd.  is a Japanese video game developer and publisher, best known for handling emulation of re-released games, such as some Sega Ages titles, Virtual Console titles for Nintendo systems, the 3D Classics series for the Nintendo 3DS and their ShotTriggers range of classic STG games. M2 has also created entirely new titles such as WiiWare games for Konami under the ReBirth moniker and more recently a new GG Aleste game. In addition, M2 currently holds the rights of Aleste series, all of SPS game plus software and all NEC Avenue and NEC Interchannel games on TurboGrafx-16 and variants, previously owned by Lightweight.', 'https://media.retroachievements.org/Images/066684.png', 'https://media.retroachievements.org/Images/067936.png', 'https://media.retroachievements.org/Images/117339.png', 'https://media.retroachievements.org/Images/117340.png', 4.1),
  (165, 81, 'Space Harrier II', 'Genesis/Mega Drive', 1, 957, 957, 957, 30, 0, 'Rail Shooter', 'Sega', 'Sega', '1988-10-29', 'Space Harrier II  is a 1988 rail shooter video game developed and published by Sega. The sequel to 1985''s Space Harrier, it was one of the original launch titles released for the Mega Drive in Japan and one of the six Sega Genesis launch titles in the United States the following year. It was later released on the Wii''s Virtual Console in December 2006, and also on the Nintendo Classics service in April 2022. Like Altered Beast, another launch title for the Mega Drive, Space Harrier II features digitized voice recordings during gameplay, and is also an example of some of the Mega Drive''s early sound, with music composed by Tokuhiko Uwabo. A graphically enhanced version included with the Sega Genesis Mini 2 was released in October 2022.', 'https://media.retroachievements.org/Images/072195.png', 'https://media.retroachievements.org/Images/000228.png', 'https://media.retroachievements.org/Images/000225.png', 'https://media.retroachievements.org/Images/000226.png', 4.1),
  (166, 1432, 'Monster World IV', 'Genesis/Mega Drive', 1, 953, 953, 953, 84, 0, 'Metroidvania', 'Westone', 'Sega', '1994-04-01', 'Monster World IV is an action-adventure platform game developed by Westone and released in Japan by Sega for the Mega Drive in April 1994. The game title is slightly confusing: It is the sixth game in the Wonder Boy series and the fourth game in the Monster World subseries. It was later released for the PlayStation 2 on March 8, 2007, as part of the Sega Ages 2500 series under the name Sega Ages 2500 Series Vol. 29: Monster World Complete Collection. It was released on the Wii''s Virtual Console service in Japan on January 15, 2008. An English-language version was released in North America and Europe for Virtual Console on May 10, 2012, with a release on Xbox Live Arcade and PlayStation Network to come on May 22, 2012. Monster World IV was the last Wonder Boy game to both be published by Sega and developed by Westone Bit Entertainment. A remake by Artdink, titled Wonder Boy: Asha in Monster World, was released in May 2021.', 'https://media.retroachievements.org/Images/020058.png', 'https://media.retroachievements.org/Images/009518.png', 'https://media.retroachievements.org/Images/017194.png', 'https://media.retroachievements.org/Images/017195.png', 4.1),
  (167, 5855, 'Shadow of the Beast', 'Genesis/Mega Drive', 1, 951, 951, 951, 30, 0, '2D Platforming, Action-Adventure', 'Reflections, WJS Design', 'Psygnosis', '1991-01-01', 'Shadow of the Beast is a 1989 platform game developed by Reflections and published by Psygnosis for the Amiga. It was later ported to several other systems. The game was known for its graphics, with many colours on screen and up to twelve levels of parallax scrolling backdrops, and for its atmospheric score composed by David Whittaker that used high-quality instrument samples.', 'https://media.retroachievements.org/Images/032134.png', 'https://media.retroachievements.org/Images/032130.png', 'https://media.retroachievements.org/Images/032132.png', 'https://media.retroachievements.org/Images/032181.png', 4.1),
  (168, 1439, 'Daze Before Christmas', 'Genesis/Mega Drive', 1, 940, 940, 940, 27, 0, '2D Platforming', 'Funcom', 'Sunsoft', '1994-01-01', 'David Martin Ruprecht is an American television and stage actor and game show host, primarily known for his work as host of the Lifetime/PAX game show Supermarket Sweep.', 'https://media.retroachievements.org/Images/063153.png', 'https://media.retroachievements.org/Images/006812.png', 'https://media.retroachievements.org/Images/006809.png', 'https://media.retroachievements.org/Images/006811.png', 4.1),
  (169, 288, '~Prototype~ Ninja Gaiden', 'Genesis/Mega Drive', 1, 937, 937, 937, 22, 0, 'Beat ''em Up', 'Opus', 'Sega', '1992-08-06', 'Ninja Gaiden  is an action game franchise created by Tecmo and featuring the ninja Ryu Hayabusa as its protagonist. The series was originally known as Ninja Ryukenden  in Japan. The word gaiden in the North American Ninja Gaiden title means side story in Japanese. The original arcade version, first two Nintendo Entertainment System games and Game Boy game were released as Shadow Warriors in PAL regions. As of 2008, the series had shipped over 7.7 million units worldwide.', 'https://media.retroachievements.org/Images/047618.png', 'https://media.retroachievements.org/Images/010120.png', 'https://media.retroachievements.org/Images/006686.png', 'https://media.retroachievements.org/Images/006685.png', 4.1),
  (170, 184, 'Art of Fighting', 'Genesis/Mega Drive', 1, 929, 929, 929, 35, 0, '2D Fighting', 'SNK', 'SNK', '1994-01-14', 'Art of Fighting, known in Japan as Dragon & Tiger Fist, is a 1992 fighting game developed and published by SNK for the Neo Geo MVS arcade system. It is the first game in the Art of Fighting series. It was eventually ported to the Neo Geo AES, Neo Geo CD, PC Engine CD-ROM², Sega Genesis, and Super Nintendo Entertainment System. The game follows Kyokugenryu Karate users Ryo Sakazaki and Robert Garcia as they travel to fight criminals from South Town in order to find Ryo''s missing sister Yuri. The game employs special moves and stronger Desperation Moves that can be performed strategically by filling the player''s energy bar and removing enemies by taunting them.', 'https://media.retroachievements.org/Images/071350.png', 'https://media.retroachievements.org/Images/011952.png', 'https://media.retroachievements.org/Images/000575.png', 'https://media.retroachievements.org/Images/000576.png', 4.1),
  (171, 311, 'Gain Ground', 'Genesis/Mega Drive', 1, 916, 916, 916, 101, 0, NULL, 'SIMS | Sanritsu', 'Sega', '1991-01-03', 'Gain Ground is a 1988 action arcade video game developed and published by Sega. It is set within a supercomputer''s simulation of war, and follows up to three players traversing through a series of forty levels themed after select periods of human history. The goal of each level, depending on the player''s choice, is either to guide at least one player character safely to an exit point or to destroy all enemies within them, both of which must be completed before a given time limit elapses.', 'https://media.retroachievements.org/Images/069979.png', 'https://media.retroachievements.org/Images/053577.png', 'https://media.retroachievements.org/Images/000191.png', 'https://media.retroachievements.org/Images/000190.png', 4.1),
  (172, 74, 'Top Gear 2', 'Genesis/Mega Drive', 1, 916, 916, 916, 68, 0, 'Racing', 'Gremlin Graphics', 'Vic Tokai', '1994-06-02', 'Top Gear 2 is a racing video game developed and published by Gremlin Interactive. A direct sequel to the 1992 game Top Gear, it was first released by Kemco for the SNES in North America in September 1993, and then the Super Famicom in Japan on December 22. It was later ported to the Amiga and Amiga CD32 in September 1994 by Gremlin Interactive, and to the Sega Genesis in September by Vic Tokai. While more realistic than its predecessor, Top Gear 2 maintained the arcade-style gameplay the series is known for.', 'https://media.retroachievements.org/Images/046589.png', 'https://media.retroachievements.org/Images/046493.png', 'https://media.retroachievements.org/Images/046492.png', 'https://media.retroachievements.org/Images/001483.png', 4.1),
  (173, 619, 'Ultimate Qix', 'Genesis/Mega Drive', 1, 906, 906, 906, 49, 0, 'Puzzle, Action', 'Taito', 'Taito', '1991-01-25', 'The Sega Genesis, known as the Mega Drive in regions outside of North America, is a 16-bit video game console that was designed and produced by Sega. First released in Japan on October 29, 1988, in North America on August 1989, and in PAL regions in 1990, the Genesis is Sega''s third console and the successor to the Master System. The system supports a library of 881 officially licensed games created both by Sega and a wide array of third-party publishers and delivered on ROM cartridges. It can also play Master System games when the separately sold Power Base Converter is installed. The Sega Genesis also sported numerous peripherals, including the Sega CD and 32X, several network services, and multiple first-party and third-party variations of the console that focused on extending its functionality. The console and its games continue to be popular among fans, collectors, video game music fans, and emulation enthusiasts. Licensed third party re-releases of the console are still being produced, and several indie game developers continue to produce games for it. Many games have also been re-released in compilations for newer consoles and offered for download on various digital distribution services, such as Virtual Console, Xbox Live Arcade, PlayStation Network, and Steam.', 'https://media.retroachievements.org/Images/017439.png', 'https://media.retroachievements.org/Images/017440.png', 'https://media.retroachievements.org/Images/017437.png', 'https://media.retroachievements.org/Images/017438.png', 4.1),
  (174, 287, 'Rambo III', 'Genesis/Mega Drive', 1, 895, 895, 895, 14, 0, 'Run & Gun', 'Sega', 'Sega', '1989-01-01', 'Rambo III is a 1988 American war action film starring Sylvester Stallone as Vietnam War veteran John Rambo. Directed by Peter MacDonald, the script was co-written by Stallone and Sheldon Lettich. It is a sequel to Rambo: First Blood Part II (1985) and the third installment in the Rambo film series. Richard Crenna reprises his role as Colonel Sam Trautman.', 'https://media.retroachievements.org/Images/004297.png', 'https://media.retroachievements.org/Images/048236.png', 'https://media.retroachievements.org/Images/048237.png', 'https://media.retroachievements.org/Images/004323.png', 4.1),
  (175, 24453, '~Homebrew~ Mega Man: The Sequel Wars - Episode Red', 'Genesis/Mega Drive', 1, 892, 892, 892, 135, 0, '2D Platforming', 'Woodfrog and the Sequel Wars Team', 'Woodfrog and the Sequel Wars Team', '2023-05-23', 'The Sega Genesis, known as the Mega Drive in regions outside of North America, is a 16-bit video game console that was designed and produced by Sega. First released in Japan on October 29, 1988, in North America on August 1989, and in PAL regions in 1990, the Genesis is Sega''s third console and the successor to the Master System. The system supports a library of 881 officially licensed games created both by Sega and a wide array of third-party publishers and delivered on ROM cartridges. It can also play Master System games when the separately sold Power Base Converter is installed. The Sega Genesis also sported numerous peripherals, including the Sega CD and 32X, several network services, and multiple first-party and third-party variations of the console that focused on extending its functionality. The console and its games continue to be popular among fans, collectors, video game music fans, and emulation enthusiasts. Licensed third party re-releases of the console are still being produced, and several indie game developers continue to produce games for it. Many games have also been re-released in compilations for newer consoles and offered for download on various digital distribution services, such as Virtual Console, Xbox Live Arcade, PlayStation Network, and Steam.', 'https://media.retroachievements.org/Images/074329.png', 'https://media.retroachievements.org/Images/073781.png', 'https://media.retroachievements.org/Images/074467.png', 'https://media.retroachievements.org/Images/073753.png', 4.1),
  (176, 4509, 'Wiz ''n'' Liz: The Frantic Wabbit Wescue', 'Genesis/Mega Drive', 1, 892, 892, 892, 55, 0, NULL, 'Bizarre Creations', 'Psygnosis', '1993-01-01', 'Wiz ''n'' Liz: The Frantic Wabbit Wescue is a platform game developed by Raising Hell Software for the Sega Mega Drive and published by Psygnosis in 1993. An Amiga port was developed by Lunatic Software. It is a humorous, cutesy platform game. With the exception of some end-of-level bosses, the game contains no enemies.', 'https://media.retroachievements.org/Images/078319.png', 'https://media.retroachievements.org/Images/059358.png', 'https://media.retroachievements.org/Images/003058.png', 'https://media.retroachievements.org/Images/003059.png', 4.1),
  (177, 402, 'Thunder Force II', 'Genesis/Mega Drive', 1, 891, 891, 891, 50, 0, NULL, 'Technosoft | Tecno Soft', 'Sega', '1989-06-15', 'Thunder Force II is a scrolling shooter developed by Technosoft. It was first released in Japan on October 15, 1988 for the X68000 computer. A year later, it was ported to the Sega Mega Drive/Genesis game console and released in Japan, Europe, and the United States. Thunder Force II was one of the six launch titles for the U.S. Genesis release. The Genesis port was later included in Thunder Force Gold Pack Volume 1 for the Sega Saturn. It was also re-released via the Nintendo Classics service on December 16, 2021. It is the second chapter of the Thunder Force series.', 'https://media.retroachievements.org/Images/078805.png', 'https://media.retroachievements.org/Images/007939.png', 'https://media.retroachievements.org/Images/020775.png', 'https://media.retroachievements.org/Images/020774.png', 4.1),
  (178, 4372, 'The Ooze', 'Genesis/Mega Drive', 1, 884, 884, 884, 27, 0, 'Action', 'Sega', 'Sega', '1995-09-22', 'The Ooze is a video game developed by Sega Technical Institute and released in 1995 for the Sega Genesis. In the game, players take the role of a slimy puddle of liquid and face off against various enemies and obstacles.', 'https://media.retroachievements.org/Images/039511.png', 'https://media.retroachievements.org/Images/009946.png', 'https://media.retroachievements.org/Images/009942.png', 'https://media.retroachievements.org/Images/009943.png', 4.1),
  (179, 157, 'Double Dragon 3: The Arcade Game', 'Genesis/Mega Drive', 1, 877, 877, 877, 12, 0, 'Beat ''em Up', 'East Technology', 'Flying Edge', '1992-01-01', 'Double Dragon 3: The Rosetta Stone is a side-scrolling beat ''em up arcade video game produced by Technōs Japan in 1990. It is the third arcade game in the Double Dragon series. Unlike its predecessors, Double Dragon 3 was not developed internally at Technōs, but was contracted to the company East Technology, resulting in a game that looks and plays differently.', 'https://media.retroachievements.org/Images/062619.png', 'https://media.retroachievements.org/Images/000742.png', 'https://media.retroachievements.org/Images/053235.png', 'https://media.retroachievements.org/Images/053236.png', 4.1),
  (180, 485, 'Arcus Odyssey', 'Genesis/Mega Drive', 1, 869, 869, 869, 24, 0, 'Shoot ''em Up', 'Wolf Team', 'Renovation Products', '1991-06-14', 'Arcus Odyssey is a 1991 action game developed by Wolf Team and released by Renovation Products for the Sega Genesis and X68000 and in 1993 for the Super Nintendo Entertainment System. The game features an isometric perspective and cooperative gameplay with hack and slash elements. It tells the story of four heroes trying to thwart the return of an evil sorceress.', 'https://media.retroachievements.org/Images/050154.png', 'https://media.retroachievements.org/Images/011944.png', 'https://media.retroachievements.org/Images/049875.png', 'https://media.retroachievements.org/Images/049876.png', 4.1),
  (181, 154, 'Doom Troopers', 'Genesis/Mega Drive', 1, 867, 867, 867, 35, 0, NULL, 'Adrenalin Entertainment', 'Playmates Interactive Entertainment', '1995-01-01', 'Mutant Chronicles: Doom Troopers is a video game released in 1995 by Adrenalin Entertainment for the Sega Genesis and Super NES gaming systems.', 'https://media.retroachievements.org/Images/008527.png', 'https://media.retroachievements.org/Images/008528.png', 'https://media.retroachievements.org/Images/008526.png', 'https://media.retroachievements.org/Images/008525.png', 4.1),
  (182, 4291, 'High Seas Havoc', 'Genesis/Mega Drive', 1, 866, 866, 866, 27, 0, '2D Platforming', 'Data East', 'Codemasters', '1993-01-01', 'Maneater is an action role-playing game developed and published by Tripwire Interactive. The player assumes control of a female bull shark who must evolve and survive in an open world so she can take revenge on a fisherman who disfigured her as a pup and killed her mother.', 'https://media.retroachievements.org/Images/063200.png', 'https://media.retroachievements.org/Images/014714.png', 'https://media.retroachievements.org/Images/014716.png', 'https://media.retroachievements.org/Images/014717.png', 4.1),
  (183, 113, 'Hellfire', 'Genesis/Mega Drive', 1, 854, 854, 854, 23, 0, 'Shoot ''em Up', 'Toaplan', 'Seismic', '1990-09-28', 'Hellfire is a 1989 horizontally scrolling shooter video game developed by Toaplan and published by Taito for Japanese arcades; in North America, it was distributed by U.S.A. Games. The first horizontal shoot ''em up title to be created by Toaplan, the game takes place in the year 2998, where a space matter known as Black Nebula, created by robot dictator Super Mech, spreads and threatens to engulf human-controlled galaxies. Players assume the role of Space Federation member Captain Lancer, taking control of the CNCS1 spacecraft in a surprise attack to overthrow the enemies using the spacecraft''s titular weapon.', 'https://media.retroachievements.org/Images/063196.png', 'https://media.retroachievements.org/Images/000330.png', 'https://media.retroachievements.org/Images/000327.png', 'https://media.retroachievements.org/Images/000328.png', 4),
  (184, 603, 'Chiki Chiki Boys', 'Genesis/Mega Drive', 1, 832, 832, 832, 30, 0, NULL, 'Capcom, Visco', 'Sega', '1992-10-16', 'Mega Twins, known as Chiki Chiki Boys in Japan and Europe is a 1990 platform video game developed and published by Capcom for arcades.', 'https://media.retroachievements.org/Images/023143.png', 'https://media.retroachievements.org/Images/005268.png', 'https://media.retroachievements.org/Images/005269.png', 'https://media.retroachievements.org/Images/005270.png', 4),
  (185, 338, 'DJ Boy', 'Genesis/Mega Drive', 1, 815, 815, 815, 17, 0, 'Beat ''em Up', 'Kaneko', 'Kaneko', '1990-05-19', 'DJ Boy (DJボーイ) is a 1989 beat ''em up arcade video game developed and published in Japan by Kaneko and in North America by Sammy. DJ Boy, also known as DJ Kid, was partially based on the hip hop culture of the U.S. cities. Many of the characters ride around on roller skates rather than walking or running.', 'https://media.retroachievements.org/Images/113699.png', 'https://media.retroachievements.org/Images/125098.png', 'https://media.retroachievements.org/Images/000579.png', 'https://media.retroachievements.org/Images/000580.png', 4),
  (186, 524, '~Prototype~ Tetris', 'Genesis/Mega Drive', 1, 810, 810, 810, 21, 0, NULL, NULL, NULL, '1989-01-01', 'Tetris is a puzzle video game created in 1985 by Alexey Pajitnov, a Soviet software engineer. In the game, falling tetromino shapes must be neatly sorted into a pile. Once a horizontal line of the board is filled in, the line disappears, granting points and preventing the pile from overflowing. Since its initial creation, this gameplay has been used in over 220 versions, released for over 70 platforms. Newer versions frequently implement additional game mechanics, some of which have become standard over time. As of December 2024, these versions collectively serve as the second-best-selling video game series with over 520 million sales, mostly on mobile devices.', 'https://media.retroachievements.org/Images/069976.png', 'https://media.retroachievements.org/Images/112015.png', 'https://media.retroachievements.org/Images/033573.png', 'https://media.retroachievements.org/Images/033574.png', 4),
  (187, 4346, 'The Lost Vikings', 'Genesis/Mega Drive', 1, 810, 810, 810, 68, 0, 'Puzzle Platforming', 'Silicon & Synapse', 'Interplay Entertainment', '1993-01-01', 'The Lost Vikings is a 1993 puzzle-platform game developed by Silicon & Synapse and published by Interplay Productions. In the game, the player controls three separate vikings with different abilities. The three vikings must work together to finish each level and find their way back home.', 'https://media.retroachievements.org/Images/071851.png', 'https://media.retroachievements.org/Images/017327.png', 'https://media.retroachievements.org/Images/017324.png', 'https://media.retroachievements.org/Images/017325.png', 4),
  (188, 41, 'Tiny Toon Adventures: ACME All-Stars', 'Genesis/Mega Drive', 1, 799, 799, 799, 39, 0, 'Sports', 'Konami', 'Konami', '1994-01-01', 'Tiny Toon Adventures: ACME All-Stars is a Tiny Toon Adventures-based sports video game released on the Sega Genesis video game console. The game was developed and published by Konami in 1994.', 'https://media.retroachievements.org/Images/055629.png', 'https://media.retroachievements.org/Images/010957.png', 'https://media.retroachievements.org/Images/010952.png', 'https://media.retroachievements.org/Images/010955.png', 4),
  (189, 105, 'Jurassic Park', 'Genesis/Mega Drive', 1, 788, 788, 788, 42, 0, 'Action Adventure', 'BlueSky Software', 'Sega', '1993-08-10', 'Jurassic Park, later referred to as Jurassic World, is an American science fiction media franchise created by Michael Crichton, centered on a disastrous attempt to create a theme park of cloned dinosaurs. It began in 1990 when Universal Pictures and Amblin Entertainment bought the rights to Crichton''s novel Jurassic Park before it was published. The book was successful, as was Steven Spielberg''s 1993 film adaptation. The film received a theatrical 3D re-release in 2013, and was selected in 2018 for preservation in the United States National Film Registry by the Library of Congress as being culturally, historically, or aesthetically significant. Crichton''s 1995 sequel novel, The Lost World, was followed by a 1997 film adaptation, also directed by Spielberg. Crichton did not write any further sequels in the series, although Spielberg would return as executive producer for each subsequent film, starting with Jurassic Park III (2001).', 'https://media.retroachievements.org/Images/045406.png', 'https://media.retroachievements.org/Images/005639.png', 'https://media.retroachievements.org/Images/005640.png', 'https://media.retroachievements.org/Images/005641.png', 4),
  (190, 8474, 'Cannon Fodder', 'Genesis/Mega Drive', 1, 783, 783, 783, 61, 0, 'Action, Shooter, Shoot-''Em-Up, Top-Down', 'Panelcomp', 'Virgin Interactive', '1994-01-01', 'Cannon Fodder is a series of war themed action games developed by Sensible Software, initially released as Cannon Fodder for the Amiga. Only two games in the series were created by Sensible, but were converted to most active systems at the time of release. A sequel, Cannon Fodder 2, was released in 1994 for Amiga and MS-DOS. A third game, Cannon Fodder 3, was made by a Russian developer and released in English in 2012.', 'https://media.retroachievements.org/Images/053306.png', 'https://media.retroachievements.org/Images/053307.png', 'https://media.retroachievements.org/Images/053304.png', 'https://media.retroachievements.org/Images/053305.png', 4),
  (191, 4377, 'OutRun 2019', 'Genesis/Mega Drive', 1, 778, 778, 778, 43, 0, NULL, 'SIMS | Sanritsu', 'Sega', '1993-03-26', 'OutRun 2019  is a 1993 racing video game for the Sega Genesis, serving as a pseudo-sequel to Out Run (1986) that takes place in the (then) future: 2019, hence the name. The object is to race against a time limit in a rocket-boosted car across four different stages around the world. Like the original Out Run, there is a fork in the road before each checkpoint, but there can also be forks within a single route.', 'https://media.retroachievements.org/Images/069356.png', 'https://media.retroachievements.org/Images/069369.png', 'https://media.retroachievements.org/Images/069366.png', 'https://media.retroachievements.org/Images/069365.png', 4),
  (192, 561, 'Landstalker: The Treasures of King Nole', 'Genesis/Mega Drive', 1, 769, 769, 769, 50, 0, 'Action-Adventure', 'Climax Entertainment', 'Sega', '1992-10-30', 'Landstalker: The Treasures of King Nole is a 1992 action role-playing video game developed by Climax Entertainment and published by Sega for the Sega Genesis. The player takes on the role of the treasure hunter Nigel as they navigate a three-dimensional world through an isometric viewpoint, solving puzzles and fighting enemies.', 'https://media.retroachievements.org/Images/079386.png', 'https://media.retroachievements.org/Images/003943.png', 'https://media.retroachievements.org/Images/003941.png', 'https://media.retroachievements.org/Images/003942.png', 4),
  (193, 25807, '~Hack~ Teenage Mutant Ninja Turtles: Shredder''s Re-Revenge', 'Genesis/Mega Drive', 1, 762, 762, 762, 25, 0, 'Beat ''em Up', 'savok', 'Hack - Streets of Rage 2', '2022-12-26', 'Video games based on the Teenage Mutant Ninja Turtles franchise have been produced since 1989, largely by Japanese video game manufacturer Konami.', 'https://media.retroachievements.org/Images/120841.png', 'https://media.retroachievements.org/Images/112426.png', 'https://media.retroachievements.org/Images/082662.png', 'https://media.retroachievements.org/Images/082663.png', 4),
  (194, 177, 'Paperboy', 'Genesis/Mega Drive', 1, 754, 754, 754, 9, 0, 'Action', 'Motivetime', 'Atari, Tengen', '1990-01-01', 'A paperboy is someone – often an older child or adolescent – who distributes printed newspapers to homes or offices on a regular route, usually by bicycle or automobile. In Western nations during the heyday of print newspapers during the early 20th century, this was often a young person''s first job, perhaps undertaken before or after school. This contrasts with the newsboy or newspaper hawker, now extremely rare in Western nations, who would sell newspapers to passersby on the street, often with very vocal promotion. They were common when multiple daily papers in every city – as many as 50 in New York City alone – competed.', 'https://media.retroachievements.org/Images/065591.png', 'https://media.retroachievements.org/Images/000395.png', 'https://media.retroachievements.org/Images/000392.png', 'https://media.retroachievements.org/Images/000393.png', 4),
  (195, 160, 'Mutant League Hockey', 'Genesis/Mega Drive', 1, 726, 726, 726, 40, 0, NULL, 'Electronic Arts', 'Electronic Arts', '1994-03-01', 'Mutant League Hockey is an ice hockey video game that was released in 1994 for the Sega Genesis. It is the follow up to Mutant League Football (1993).', 'https://media.retroachievements.org/Images/078871.png', 'https://media.retroachievements.org/Images/010150.png', 'https://media.retroachievements.org/Images/010170.png', 'https://media.retroachievements.org/Images/010171.png', 4),
  (196, 18481, '~Unlicensed~ Bomber', 'Genesis/Mega Drive', 1, 723, 723, 723, 8, 0, 'Action', 'Tectoy', 'AtGames, KDS', '2008-01-01', 'A bomber is a military combat aircraft that utilizes air-to-ground weaponry to drop bombs, launch torpedoes, or deploy air-launched cruise missiles.', 'https://media.retroachievements.org/Images/102648.png', 'https://media.retroachievements.org/Images/052740.png', 'https://media.retroachievements.org/Images/052741.png', 'https://media.retroachievements.org/Images/052742.png', 4),
  (197, 4140, 'Batman Returns', 'Genesis/Mega Drive', 1, 721, 721, 721, 23, 0, 'Beat ''em Up', 'Malibu Interactive', 'Sega', '1992-01-01', 'Batman Returns is a 1992 American superhero film directed by Tim Burton and written by Daniel Waters. Based on the DC Comics character Batman, it is the sequel to Batman (1989), also directed by Burton, and the second installment in the Batman film series (1989–1997). The cast includes Michael Keaton, Danny DeVito, Michelle Pfeiffer, Christopher Walken, Michael Gough, Pat Hingle, and Michael Murphy. Set during Christmas in Gotham City, the film follows Batman (Keaton) as he confronts corrupt businessman Max Shreck (Walken) and deformed crime boss Oswald Cobblepot / the Penguin (DeVito), whose bid for power threatens the city. Their schemes are further complicated by Shreck''s former secretary Selina Kyle (Pfeiffer), who seeks revenge against him as Catwoman.', 'https://media.retroachievements.org/Images/107705.png', 'https://media.retroachievements.org/Images/086507.png', 'https://media.retroachievements.org/Images/010917.png', 'https://media.retroachievements.org/Images/010918.png', 4),
  (198, 622, 'Space Invaders ''91', 'Genesis/Mega Drive', 1, 712, 712, 712, 22, 0, 'Shoot ''em Up', 'Taito', 'Taito', '1991-01-01', 'The Sega Genesis, known as the Mega Drive in regions outside of North America, is a 16-bit video game console that was designed and produced by Sega. First released in Japan on October 29, 1988, in North America on August 1989, and in PAL regions in 1990, the Genesis is Sega''s third console and the successor to the Master System. The system supports a library of 881 officially licensed games created both by Sega and a wide array of third-party publishers and delivered on ROM cartridges. It can also play Master System games when the separately sold Power Base Converter is installed. The Sega Genesis also sported numerous peripherals, including the Sega CD and 32X, several network services, and multiple first-party and third-party variations of the console that focused on extending its functionality. The console and its games continue to be popular among fans, collectors, video game music fans, and emulation enthusiasts. Licensed third party re-releases of the console are still being produced, and several indie game developers continue to produce games for it. Many games have also been re-released in compilations for newer consoles and offered for download on various digital distribution services, such as Virtual Console, Xbox Live Arcade, PlayStation Network, and Steam.', 'https://media.retroachievements.org/Images/041389.png', 'https://media.retroachievements.org/Images/041388.png', 'https://media.retroachievements.org/Images/041386.png', 'https://media.retroachievements.org/Images/041387.png', 4),
  (199, 10340, '~Hack~ Sonic the Hedgehog 2 XL', 'Genesis/Mega Drive', 1, 704, 704, 704, 33, 0, '2D Platforming', 'Captain Bozo, Ranger', 'Hack - Sonic the Hedgehog 2', '2010-07-12', 'Homebrew is a term for software produced by hobbyists for proprietary video game consoles, which are not intended to be user-programmable.', 'https://media.retroachievements.org/Images/092254.png', 'https://media.retroachievements.org/Images/116695.png', 'https://media.retroachievements.org/Images/043847.png', 'https://media.retroachievements.org/Images/043848.png', 4),
  (200, 4382, 'Panorama Cotton', 'Genesis/Mega Drive', 1, 694, 694, 694, 65, 0, 'Rail Shooter', 'Success', 'Sunsoft', '1994-08-12', 'Panorama Cotton is a 1994 rail shooter video game developed by Success and published by Sunsoft for the Mega Drive exclusively in Japan on August 12, 1994. Panorama Cotton is the third entry in the Cotton series and made a major departure from the original gameplay formula of prior Cotton entries; instead of being a side-scrolling shooter like the others, it is a pseudo-3D shooter in the style of Sega''s Space Harrier.', 'https://media.retroachievements.org/Images/028281.png', 'https://media.retroachievements.org/Images/028279.png', 'https://media.retroachievements.org/Images/028271.png', 'https://media.retroachievements.org/Images/028272.png', 4);
